INSERT INTO `ref_indicator_grades` VALUES (1,1,'A','Penegakan integritas dan nilai etika telah diperbaiki secara berkelanjutan sehingga tercipta suasana kerja organisasi yang kondusif yang dapat mendorong kinerja para pegawai secara optimal','- Setiap individu dalam organisasi dapat mendorong penerapan nilai-nilai organisasi\r\n- Setiap individu mendukung pencapaian kinerja organisasi\r\n- Keberhasilan pencapaian kinerja organisasi dapat dihubungkan dengan integritas dan perilaku individu serta mempengaruhi remunerasi individu','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(2,1,'B','Kebijakan dan implementasi organisasi telah dievaluasi untuk meningkatkan integritas dan nilai etika para pegawai','Kebijakan dan implementasi telah dievaluasi dengan ketentuan:\r\n- Berkala\r\n- Terdokumentasi\r\n- Dilakukan untuk menangani residual risk\r\n- Hasil evaluasi telah ditindak lanjuti \r\n- Perbaikan telah menghasilkan kinerja yang lebih baik','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(3,1,'C','Penegakan integritas dan nilai etika telah dilaksanakan oleh pegawai dalam pelaksanaan tugas dan fungsinya dalam organisasi','- Terdapat wujud keteladanan dari pimpinan atas nilai organisasi \r\n- Terdapat praktik pembangunan integritas dan nilai etika\r\n- Terdapat praktik penegakan nilai etika \r\n- Terdapat bukti penegakan disiplin\r\n- Terdapat pemberian punishment bagi pegawai yang melanggar dan reward bagi pegawai yang menegakan integritas dan nilai etika \r\n- Proses tersebut di atas dilaksanakan melalui struktur dan mekanisme yang ditetapkan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(4,1,'D','Kebijakan penegakan integritas dan nilai etika organisasi telah dipahami oleh seluruh pegawai','Kebijakan telah dikomunikasikan dan dipahami oleh:\r\n- Pimpinan (struktural)\r\n- Penanggungjawab penegakan integritas dan nilai etika\r\n- Pegawai','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(5,1,'E','Terdapat kebijakan penegakan integritas dan nilai etika untuk seluruh pegawai dalam organisasi','Kebijakan telah mengatur:\r\n- Keteladanan pimpinan\r\n- Upaya pembangunan integritas\r\n- Nilai etika \r\n- Penegakan disiplin\r\n- Pemberian reward and punishment  \r\n- Penetapan struktur dan mekanisme penanganan penegakan integritas dan nilai etika','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(6,2,'A','Pengelolaan kompetensi SDM telah diperbaiki secara berkelanjutan dan secara optimal mampu mendukung pencapaian tujuan organisasi','- Setiap posisi dalam organisasi telah diisi oleh SDM sesuai dengan standar kompetensinya \r\n- Penerapan standar kompetensi telah berhasil meningkatkan kinerja yang memberikan dampak bagi pencapaian tujuan organisasi\r\n- Keberhasilan pencapaian kinerja organisasi dapat dihubungkan dengan kompetensi SDM-nya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(7,2,'B','Standar kompetensi organisasi dan implementasi/pemanfaatannya telah dievaluasi untuk mengetahui efektivitasnya','Standar kompetensi dan implementasi/pemanfaatannya telah dievaluasi dengan ketentuan:\r\n- Berkala\r\n- Terdokumentasi\r\n- Dilakukan untuk menangani residual risk\r\n- Hasil evaluasi telah ditindak lanjuti \r\n- Perbaikan telah menghasilkan kinerja yang lebih baik','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(8,2,'C','Standar kompetensi telah diimplementasikan/dimanfaatkan dalam pengelolaan/pembinaan SDM organisasi','- Standar kompetensi dimanfaatkan untuk menyusun analisis kompetensi SDM\r\n- Analisis kompetensi yang disusun berdasarkan standar kompetensi dimanfaatkan untuk perencanaan rekrutmen SDM\r\n- Analisis kompetensi yang disusun berdasarkan standar kompetensi dimanfaatkan untuk perencanaan pengembangan SDM\r\n- Standar kompetensi dimanfaatkan sebagai dasar pertimbangan pengisian jabatan (mutasi/ promosi/ seleksi)','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(9,2,'D','Standar kompetensi telah dikomunikasikan dan dipahami oleh seluruh pegawai organisasi','Standar kompetensi telah dikomunikasikan dan dipahami oleh:\r\n- Pimpinan (struktural)\r\n- Penanggungjawab pengelolaan SDM\r\n- Pegawai\r\nsesuai tusinya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(10,2,'E','Terdapat standar kompetensi yang jelas untuk seluruh jabatan dan posisi dalam organisasi','Terdapat standar kompetensi yang mengatur:\r\n- Standar kompetensi SDM struktural\r\n- Standar kompetensi SDM fungsional\r\n- Standar kompetensi manajerial\r\n- Standar kompetensi sosio kultural\r\n- Standar kompetensi teknis','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(11,3,'A','Penerapan manajemen kinerja, pengelolaan keuangan, manajemen SDM, serta manajemen risiko dapat meningkatkan efektivitas dan efisiensi kinerja seluruh level pimpinan dan pegawai','Sudah Jelas','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(12,3,'B','Pimpinan organisasi melaksanakan evaluasi berkala atas kebijakan pengendalian intern dan berupaya mengatasi permasalahan yang berkaitan dengan lingkungan pengendalian yang kondusif','a. K/L/D melakukan evaluasi untuk meninjau kembali relevansi kebijakan beserta implementasinya dengan ketentuan sebagai berikut:\r\n1. Telah dilaksanakan evaluasi berkala; \r\n2. Evaluasi dilaksanakan untuk menangani residual risk;\r\n3. Tindak lanjut atas hasil evaluasi  telah dilaksanakan;\r\nb. Pimpinan organisasi terbuka atas masukan dari pegawai dan adaptif terhadap perubahan.\r\nc. Keluhan dari pegawai atas keterbatasan/masalah sumberdaya dukungan pelaksanaan pekerjaan dapat diatasi.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(13,3,'C','Pimpinan organisasi melaksanakan kebijakan dan didukung dengan SDM yang bekerja sesuai dengan kebijakan yang ditetapkan','a. Pimpinan organisasi menerapkan manajemen berbasis kinerja dan mempertimbangkan risiko dalam pengambilan keputusan.\r\nb. Pimpinan organisasi memberikan keteladanan dalam beretika, berintegritas, ketaatan terhadap perundang-undangan, dan berkinerja secara efektif dan efisien.\r\nc. Pegawai mendukung pimpinan organisasi dengan hadir dan bekerja sesuai dengan ketentuan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(14,3,'D','Pimpinan organisasi terlibat dalam penyusunan dan penetapkan kebijakan yang mendukung penciptaan lingkungan kerja yang kondusif untuk pencapaian tujuan organisasi serta memahami substansi kebijakan pengendalian intern dan mendorong penerapan kebijakan dalam berbagai interaksi kepada jajaran di bawahnya','a. Pimpinan organisasi telah memahami substansi dari kebijakan yang telah ditetapkan.\r\nb. Pimpinan organisasi mengarahkan pegawai agar dapat bekerja selaras dengan kebijakan, melalui:\r\n1. Rapat internal.\r\n2. Upacara/apel pagi.\r\n3. Forum diskusi/jam pimpinan.\r\n4. Interaksi informal.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(15,3,'E','Pimpinan organisasi terlibat dalam penyusunan dan penetapkan kebijakan yang mendukung penciptaan lingkungan kerja yang kondusif untuk pencapaian tujuan organisasi','Pimpinan organisasi terlibat dalam penyusunan kebijakan yang mendukung penciptaan lingkungan kerja yang kondusif untuk pencapaian tujuan organisasi, antara lain kebijakan terkait manajemen kinerja, manajemen keuangan dan aset, manajemen SDM, serta manajemen risiko.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(16,4,'A','Sudah mengalokasikan sumber daya secara memadai untuk penerapan manajemen risiko pada tingkat operasional unit kerja, strategis unit kerja, dan strategis K/L/D','a. Instansi Pemerintah telah menganggarkan dana implementasi manajemen risiko seperti rapat terkait manajemen risiko, identifikasi dan analisis risiko, penyusunan profil risiko, implementasi RTP, kegiatan monitoring dan reviu  dalam rencana kerja/DPA/DIPA  dan dalam implementasi manajemen risiko tidak terkendala kekurangan dana implementasi ditingkat operasional unit kerja, strategis unit kerja, dan strategis K/L/D\r\nb. Minimal 70% SDM yang menjadi anggota UPR pada tingkat operasional dan strategis unit kerja serta strategis K/L/D diisi oleh orang yang berkompeten dalam bidang manajemen risiko','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(17,4,'B','Sudah mengalokasikan sumber daya secara memadai untuk penerapan manajemen risiko pada tingkat operasional unit kerja dan strategis unit kerja namun pada tingkat srategis K/L/D belum memadai','a. Instansi Pemerintah telah menganggarkan dana implementasi manajemen risiko seperti rapat terkait manajemen risiko, identifikasi dan analisis risiko, penyusunan profil risiko, implementasi RTP, kegiatan monitoring dan reviu  dalam rencana kerja/DPA/DIPA  dan dalam implementasi manajemen risiko tidak terkendala kekurangan dana implementasi ditingkat operasional dan strategis unit kerja, namun masih terkendala kekurangan dana pada tingkat  strategis K/L/D dan\r\nb. Minimal 70% SDM yang menjadi anggota UPR pada tingkat operasional dan strategis unit kerja diisi oleh orang yang berkompeten dalam bidang manajemen risiko serta kurang dari 70% SDM yang menjadi anggota UPR pada tingkat Strategis K/L/D diisi oleh orang yang berkompeten dalam bidang manajemen risiko','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(18,4,'C','Sudah mengalokasikan sumber daya secara memadai untuk penerapan manajemen risiko pada tingkat operasional unit kerja dan strategis unit kerja','a. Instansi Pemerintah telah menganggarkan dana implementasi manajemen risiko seperti rapat terkait manajemen risiko, identifikasi dan analisis risiko, penyusunan profil risiko, implementasi RTP, kegiatan monitoring dan reviu  dalam rencana kerja/DPA/DIPA  dan dalam implementasi manajemen risiko tidak terkendala kekurangan dana implementasi ditingkat operasional dan strategis unit kerja\r\nb. Minimal 70% SDM yang menjadi anggota UPR pada tingkat operasional dan strategis unit kerja diisi oleh orang yang berkompeten dalam bidang manajemen risiko','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(19,4,'D','Sudah mengalokasikan sumber daya secara memadai untuk penerapan manajemen risiko pada tingkat operasional unit kerja namun pada tingkat strategis unit kerja belum memadai','a. Instansi Pemerintah telah menganggarkan dana implementasi manajemen risiko pada tingkat operasional unit kerja seperti rapat terkait manajemen risiko, identifikasi dan analisis risiko, penyusunan profil risiko, implementasi RTP, kegiatan monitoring dan reviu  dalam rencana kerja/DPA/DIPA secara memadai, namun belum memadai pada tingkat strategis unit kerja, dan/atau\r\nb. Kurang dari 70% SDM yang menjadi anggota UPR pada tingkat operasional Unit Kerja diisi oleh orang yang berkompeten dalam bidang manajemen risiko','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(20,4,'E','Sudah mengalokasikan sumber daya untuk penerapan manajemen risiko pada tingkat operasional unit kerja namun belum memadai','a. Instansi Pemerintah telah menganggarkan dana implementasi manajemen risiko pada tingkat operasional unit kerja seperti rapat terkait manajemen risiko, identifikasi dan analisis risiko, penyusunan profil risiko, implementasi RTP, kegiatan monitoring dan reviu  dalam rencana kerja/DPA/DIPA namun belum memadai, dan/atau\r\nb. Kurang dari 70% SDM yang menjadi anggota UPR pada tingkat operasional Unit Kerja diisi oleh orang yang berkompeten dalam bidang manajemen risiko','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(21,5,'A','Seluruh pengambilan keputusan strategis K/L/D, strategis unit kerja, dan operasional unit kerja telah mempertimbangkan risiko dan memberikan dampak bagi pencapaian tujuan organisasi','Seluruh keputusan pimpinan instansi maupun pimpinan unit kerja secara umum menggunakan informasi terkait risiko di tingkat operasional unit kerja, strategis unit kerja, dan strategis K/L/D dan memberikan dampak bagi pencapaian tujuan organisasi','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(22,5,'B','Seluruh pengambilan keputusan strategis K/L/D, strategis unit kerja, dan operasional unit kerja telah mempertimbangkan risiko','Seluruh keputusan pimpinan instansi maupun pimpinan unit kerja secara umum menggunakan informasi terkait risiko di tingkat operasional unit kerja, strategis unit kerja, dan strategis K/L/D','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(23,5,'C','Seluruh pengambilan keputusan strategis unit kerja dan operasional unit kerja telah mempertimbangkan risiko','Seluruh keputusan pimpinan instansi maupun pimpinan unit kerja secara umum menggunakan informasi terkait risiko di tingkat operasional dan strategis unit kerja','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(24,5,'D','Seluruh pengambilan keputusan operasional unit kerja telah mempertimbangkan risiko','Seluruh keputusan pimpinan instansi maupun pimpinan unit kerja secara umum menggunakan informasi terkait risiko di tingkat operasional','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(25,5,'E','Sebagian pengambilan keputusan operasional unit kerja telah mempertimbangkan risiko','Sebagian keputusan pimpinan instansi maupun pimpinan unit kerja secara umum menggunakan informasi terkait risiko di tingkat operasional','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(26,6,'A','Kinerja penerapan manajemen risiko digunakan sebagai dasar penilaian kinerja pada seluruh UPR tingkatan operasional unit kerja, seluruh UPR tingkatan strategis unit kerja, dan UPR tingkat strategis K/L/D secara memadai dan telah dievaluasi pencapaiannya','Kinerja penerapan manajemen risiko sudah digunakan sebagai indikator kinerja pada dokumen perencanaan UPR tingkat strategis K/L/D, seluruh UPR tingkatan strategis unit kerja, dan seluruh UPR tingkatan operasional unit kerja  secara tepat, telah diukur pencapaiannya, serta dievaluasi pencapaiannya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(27,6,'B','Kinerja penerapan manajemen risiko digunakan sebagai dasar penilaian kinerja pada seluruh UPR tingkatan operasional unit kerja, seluruh UPR tingkatan strategis unit kerja, dan UPR tingkat strategis K/L/D secara memadai','Kinerja penerapan manajemen risiko sudah digunakan sebagai indikator kinerja pada dokumen perencanaan UPR tingkat strategis K/L/D, seluruh UPR tingkatan strategis unit kerja, dan seluruh UPR tingkatan operasional unit kerja  secara tepat  dan telah diukur pencapaiannya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(28,6,'C','Kinerja penerapan manajemen risiko digunakan sebagai dasar penilaian kinerja pada seluruh UPR tingkatan operasional unit kerja dan seluruh UPR tingkatan strategis unit kerja secara memadai','Kinerja penerapan manajemen risiko sudah digunakan sebagai indikator kinerja pada dokumen perencanaan seluruh UPR tingkatan strategis unit kerja dan seluruh UPR tingkatan operasional unit kerja  secara tepat  dan telah diukur pencapaiannya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(29,6,'D','Kinerja penerapan manajemen risiko digunakan sebagai dasar penilaian kinerja pada seluruh UPR tingkatan operasional unit kerja secara memadai','Kinerja penerapan manajemen risiko sudah digunakan sebagai indikator kinerja pada dokumen perencanaan seluruh UPR tingkatan operasional unit kerja  secara tepat  dan telah diukur pencapaiannya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(30,6,'E','Kinerja penerapan manajemen risiko digunakan sebagai dasar penilaian kinerja pada sebagian UPR tingkatan operasional unit kerja secara memadai','Kinerja penerapan manajemen risiko sudah digunakan sebagai indikator kinerja pada sebagian dokumen perencanaan tingkatan operasional unit kerja secara tepat  dan telah diukur pencapaiannya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(31,7,'A','K/L/D memiliki fleksibilitas untuk menyesuaikan struktur organisasi dalam rangka mendukung perubahan proses bisnis dan perubahan perencanaan strategis','Perbaikan struktur organisasi dan tata laksana dapat dilakukan secara berkelanjutan dengan dukungan teknologi informasi yang terintegrasi untuk mengelola arus data dan informasi dalam menjalanan fungsi-fungsi dalam proses bisnis organisasi. sehingga kedudukan fungsi berada di atas struktur.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(32,7,'B','Efisiensi dan efektivitas struktur organisasi dapat dilihat secara berkala melalui pengujian atas pelaksanaan proses bisnis organisasi dan ketepatannya dengan perencanaan strategis','K/L/D melakukan evaluasi atas K/SOP terkait struktur organisasi dan tata laksana beserta implementasinya antara lain dengan ketentuan sebagai berikut:\r\na. Evaluasi dilaksanakan untuk menangani residual risk;\r\nb. Terdapat duplikasi fungsi karena struktur yang tidak efektif/efisien;\r\nc. Arus data dan informasi yang tidak handal dalam pelaksanaan proses bisnis;\r\nd. Perubahan lingkungan strategis.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(33,7,'C','Struktur organisasi dijalankan sesuai proses bisnis organisasi dengan SDM yang mencukupi','- Struktur organisasi telah ditindaklanjuti dengan implementasi/pelaksanaan kegiatan organisasi sesuai proses bisnis;\r\n- Proses bisnis telah dijabarkan dengan SOP\r\n- Organisasi telah menerapkan kebijakan/SOP yang mengatur mengenai hubungan dan jenjang pelaporan intern/arus data dan informasi.\r\n- Organisasi telah memetakan kebutuhan pegawai untuk mendukung proses bisnis yang diantaranya mengatur mengenai analisis beban kerja untuk pimpinan dan pegawai.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(34,7,'D','Proses bisnis organisasi dapat didukung dengan struktur organisasi yang ditetapkan dan personel pada setiap lini mengetahui arus data dan informasi yang diperlukan dalam melaksanaan tugas dan fungsinya','a. Struktur organisasi dan tata laksana sesuai dengan proses bisnis yang ditetapkan dengan mempertimbangkan: \r\n- Ukuran dan sifat kegiatan.      \r\n- Faktor-faktor yang menjadi pertimbangan sentralisasi/desentralisasi organisasi.\r\n- Struktur organisasi harus mampu memfasilitasi arus informasi di dalam instansinya.\r\nb. Struktur organisasi dan tata laksana telah dikomunikasikan dan dipahami.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(35,7,'E','Terdapat penetapan struktur, tugas, dan fungsi organisasi','Adanya struktur organisasi dan tata laksana yang disusun yang mengacu kepada peraturan terkait.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(36,8,'A','Pimpinan organisasi memiliki akses untuk melihat proses pendelegasian wewenang dan tanggungjawab yang diberikan dan memonitor pelaksanaan tugas fungsi yang dijalankan untuk menjamin tujuan percepatan yang diharapkan dan mendukung perbaikan secara berkelanjutan.','a. Terdapat tools untuk memonitor pelaksanaan wewenang dan tanggungjawab yang diberikan secara berjenjang dan menampung pelaporan atas pelaksanaan wewenang dan tanggungjawab kepada jenjang di atasnya.\r\nb. Kemudahan akses memungkinkan pimpinan untuk memberikan teguran/arahan atas pelaksanaan wewenang dan tanggung jawab pelaksanaan kegiatan sebelum menyalahi prosedur yang ditetapkan; \r\nc. penerima manfaat/stakeholder memberikan feedback yang baik atas kecepatan respon organisasi terhadap kebutuhan mereka.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(37,8,'B','Efisiensi dan efektivitas pelaksanaan wewenang dan tanggung jawab organisasi yang didelegasikan dapat dilihat melalui evaluasi berkala atas pelaksanaan wewenang dan tanggungjawab serta analisis terhadap kualitas hasil pelaksanaan tugas/fungsi yang dilaksanakan (respon stakeholder)','Organisasi melakukan evaluasi atas kebijakan/prosedur terkait  pendelegasian wewenang dan tanggung jawab beserta implementasinya dengan ketentuan sebagai berikut:\r\na. Telah dilaksanakan evaluasi berkala; \r\nb. Evaluasi dilaksanakan untuk menangani residual risk;\r\nc. Tindak lanjut atas hasil evaluasi  telah dilaksanakan.\r\nd. Menindaklanjuti keluhan/kekurangan kualitas pelaksanaan tugas fungsi yang disampaikan oleh stakeholder.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(38,8,'C','Pelaksanaan tugas dan fungsi yang didelegasikan dilaksanakan sesuai dengan kebijakan/prosedur yang ditetapkan','a Tugas fungsi dan program/kegiatan telah dilaksanakan dengan menerapkan pendelegasian wewenang dan tanggung jawab sebagaimana diatur dalam kebijakan/prosedur yang ditetapkan;\r\nb. Pihak-pihak yang menerima pendelegasian telah melaksanakan tugas dan fungsinya sesuai dengan prosedur dan menyampaikan pelaporan kepada pihak yg memberikan wewenang secara berkala sesuai kebijakan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(39,8,'D','Kegiatan/prosedur yang dalam pelaksanaannya telah didelegasikan kepada struktur dibawahnya telah dipahami dan diketahui oleh pihak terkait','a.Kebijakan/prosedur yang mengatur pelaksanaan pendelegasian wewenang dan tanggung jawab telah dipahami oleh pegawai yang berkepentingan;\r\nb. Kebijakan/prosedur yang mengatur pelaksanaan pendelegasian wewenang dan tanggung jawab telah dikomunikasikan kepada seluruh pegawai dan stakeholder.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(40,8,'E','Pimpinan organisasi menetapkan kebijakan terkait wewenang dan tanggung jawab pelaksanaan kegiatan kepada struktur di bawahnya secara berjenjang','Organisasi memiliki kebijakan/prosedur yang mengatur pendelegasian wewenang dan tanggung jawab dalam pelaksanaan tugas fungsi dan program/kegiatan dalam rangka mendukung pencapaian tujuan organisasi yang memuat antara lain:\r\n- Prosedur pelaksanaan wewenang dan tanggungjawab yang didelegasikan;\r\n- Alur hubungan vertikal serta horizontal dan kejelasan ruang lingkung pendelegasian wewenang dan tanggung jawab;\r\n- Kewajiban dan pertanggungjawaban pihak yang diberikan wewenang kepada pihak yang memberikan wewenang.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(41,9,'A','Pengelolaan SDM telah diperbaiki secara berkelanjutan dan secara optimal mampu mendukung pencapaian tujuan organisasi','Perbaikan berkelanjutan telah menghasilkan:\r\n- Pengelolaan SDM telah berhasil meningkatkan kinerja yang memberikan dampak bagi pencapaian tujuan organisasi\r\n- Keberhasilan pencapaian kinerja organisasi dapat dihubungkan dengan pengelolaan SDM-nya\r\n- Pengelolaan SDM mampu meningkatkan kepuasan kerja pegawai','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(42,9,'B','Kebijakan dan implementasi terkait pengelolaan SDM organisasi telah dievaluasi sehingga dapat diketahui efektivitasnya','Kebijakan dan implementasi telah dievaluasi dengan ketentuan:\r\n- Berkala\r\n- Terdokumentasi\r\n- Dilakukan untuk menangani residual risk\r\n- Hasil evaluasi telah ditindak lanjuti \r\n- Perbaikan telah menghasilkan kinerja yang lebih baik','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(43,9,'C','Pengelolaan SDM telah dilaksanakan sejak rekrutmen sampai dengan pemberhentian pegawai sesuai kebijakan/prosedur yang ditetapkan','- Pengelolaan SDM dilakukan sesuai dengan kebijakan/prosedur yang ditetapkan\r\n- Pengelolaan SDM dilakukan sesuai dengan perencanaan yang disusun\r\n- Terdapat database kepegawaian yang update dan handal yang dapat dimanfaatkan untuk perencanaan pengelolaan SDM\r\n- Pengelolaan SDM dilakukan sebagai upaya untuk menangani risiko yang disebabkan kelemahan SDM/Man','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(44,9,'D','Kebijakan terkait pengelolaan SDM telah dikomunikasikan dan dipahami oleh pihak yang berkepentingan dalam organisasi','- Kebijakan telah dipahami oleh penanggungjawab pengelolaan SDM\r\n- Kebijakan telah dikomunikasikan kepada pimpinan (struktural), pegawai','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(45,9,'E','Terdapat kebijakan yang mengatur pengelolaan SDM sejak rekrutmen sampai dengan pemberhentian pegawai','Kebijakan telah mengatur:\r\n- Prosedur penerimaan pegawai\r\n- Prosedur penilaian kinerja individu pegawai\r\n- Prosedur kenaikan pangkat, jabatan, golongan\r\n- Prosedur kenaikan gaji\r\n- Prosedur pengembangan kompetensi (diklat, tugas belajar, ijin belajar)\r\n- Prosedur mutasi\r\n- Prosedur seleksi\r\n- Prosedur pemberhentian pegawai\r\n- Prosedur pensiun\r\n- Prosedur supervisi oleh pimpinan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(46,10,'A','Terdapat upaya peningkatan kompetensi dan keterampilan terkait manajemen risiko yang memadai dengan cakupan seluruh pegawai dan telah dievaluasi pencapaiannya','A. Kriteria upaya peningkatan kompetensi yang memadai:\r\n1. Memiliki program pelatihan/sertifikasi terkait manajemen risiko baik tahunan maupun lima tahunan baik ditingkat K/L/Pemerintah daerah maupun Kerja/OPD;\r\n2. Unit Kerja Eseon I/OPD memiliki program in house training tahunan; \r\n3. Instansi Pemerintah telah melaksanakan program pelatihan/sertifikasi tersebut dan dibuktikan dengan adanya laporan pelatihan dan bukti perolehan sertifikat keahlian (setiap Unit Kerja Eseon I/OPD terdapat pegawai yang memiliki sertifikat keahlian); \r\n4. In House Training telah dilaksanakan setidaknya satu kali dalam satu semester oleh masing-masing Unit Kerja Eseon I/OPD serta instruktur harus orang yang telah memiliki sertifikat keahlian; \r\n\r\nB. Kriteria Output:\r\nPelatihan dan in house training untuk meningkatkan kompetensi telah dilakukan untuk setiap tingkatan risiko:\r\n1. Strategis K/L/D untuk Eselon I adalah lebih dari 90% pejabat;\r\n2. Strategis Unit Eselon I/OPD untuk Eselon II adalah lebih dari 90% pejabat;\r\n3. Operasional Kerja/OPD untuk Eselon III ke atas sampai dengan staf adalah lebih dari 90% pejabat dan staff di level ini.\r\n\r\nC. Terdapat evaluasi atas dampak peningkatan kompetensi dan ketrampilan terhadap kualitas proses dan hasil manajemen risiko','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(47,10,'B','Terdapat upaya peningkatan kompetensi dan keterampilan terkait manajemen risiko yang memadai dengan cakupan seluruh pegawai','A. Kriteria upaya peningkatan kompetensi yang memadai:\r\n1. Memiliki program pelatihan/sertifikasi terkait manajemen risiko baik tahunan maupun lima tahunan baik ditingkat K/L/Pemerintah daerah maupun Kerja/OPD;\r\n2. Unit Kerja Eseon I/OPD memiliki program in house training tahunan; \r\n3. Instansi Pemerintah telah melaksanakan program pelatihan/sertifikasi tersebut dan dibuktikan dengan adanya laporan pelatihan dan bukti perolehan sertifikat keahlian (setiap Unit Kerja Eseon I/OPD terdapat pegawai yang memiliki sertifikat keahlian); \r\n4. In House Training telah dilaksanakan setidaknya satu kali dalam satu semester oleh masing-masing Unit Kerja Eseon I/OPD serta instruktur harus orang yang telah memiliki sertifikat keahlian; \r\n\r\nB. Kriteria Output:\r\nPelatihan dan in house training untuk meningkatkan kompetensi telah dilakukan untuk setiap tingkatan risiko:\r\n1. Strategis K/L/D untuk Eselon I adalah lebih dari 90% pejabat;\r\n2. Strategis Unit Eselon I/OPD untuk Eselon II adalah lebih dari 90% pejabat;\r\n3. Operasional Kerja/OPD untuk Eselon III ke atas sampai dengan staf adalah lebih dari 90% pejabat dan staff di level ini.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(48,10,'C','Terdapat upaya peningkatan kompetensi dan keterampilan terkait manajemen risikoyang memadai dengan cakupan sebagian besar pegawai','A. Kriteria upaya peningkatan kompetensi yang memadai:\r\n1. Memiliki program pelatihan/sertifikasi terkait manajemen risiko baik tahunan maupun lima tahunan baik ditingkat K/L/Pemerintah daerah maupun Unit Kerja/OPD;\r\n2. Unit Kerja/OPD memiliki program in house training tahunan; \r\n3. Instansi Pemerintah telah melaksanakan program pelatihan/sertifikasi tersebut dan dibuktikan dengan adanya laporan pelatihan dan bukti perolehan sertifikat keahlian (setiap Unit Kerja/OPD terdapat pegawai yang memiliki sertifikat keahlian); \r\n4. In House Training telah dilaksanakan setidaknya satu kali dalam satu semester oleh masing-masing unit Kerja/OPD  serta instruktur harus orang yang telah memiliki sertifikat keahlian; \r\n\r\nB. Kriria Output:\r\nPelatihan dan in house training untuk meningkatkan kompetensi telah dilakukan untuk setiap tingkatan risiko:\r\n1. Strategis Pemda untuk Eselon I adalah 71%-90% pejabat;\r\n2. Strategis Unit Eselon I/OPD untuk Eselon II adalah 71%-90% pejabat;\r\n3. Operasional Unit Eselon I/OPD untuk Eselon III ke atas sampai dengan staf adalah 71%-90% pejabat dan staff di level ini.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(49,10,'D','Terdapat upaya peningkatan kompetensi dan keterampilan terkait manajemen risiko yang memadai dengan cakupan sebagian pegawai','A. Kriteria Memadai:\r\n1. Memiliki program pelatihan/sertifikasi terkait manajemen risiko baik tahunan maupun lima tahunan baik ditingkat K/L/Pemerintah daerah maupun  Unit Kerja/OPD;\r\n2.  Unit Kerja/OPD memiliki program in house training tahunan; \r\n3. Instansi Pemerintah telah melaksanakan program pelatihan/sertifikasi tersebut dan dibuktikan dengan adanya laporan pelatihan dan bukti perolehan sertifikat keahlian (setiap Unit Kerja/OPD terdapat pegawai yang memiliki sertifikat keahlian); \r\n4. In House Training telah dilaksanakan setidaknya satu kali dalam satu semester oleh masing2  Unit Kerja/OPD serta instruktur harus orang yang telah memiliki sertifikat keahlian; \r\n\r\nB. Kriteria Output:\r\nPelatihan dan in house training untuk meningkatkan kompetensi telah dilakukan untuk setiap tingkatan risiko:\r\n1. Strategis K/L/D untuk Eselon I adalah 50% - 70% pejabat;\r\n2. Strategis  Unit Eselon I/OPD untuk Eselon II adalah 50% -70% pejabat;\r\n3. Operasional  Unit Eselon I/OPD untuk Eselon III ke atas sampai dengan staf adalah 50% -70% pejabat dan staff di level ini.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(50,10,'E','Terdapat upaya peningkatan kompetensi dan keterampilan terkait manajemen risiko namun belum memadai','Kriteria belum memadai apabila terdapat parameter point 1-4 dalam kriteria memadai tidak terpenuhi.\r\nKriteria Memadai:\r\n1. Memiliki program pelatihan/sertifikasi terkait manajemen risiko baik tahunan maupun lima tahunan baik ditingkat K/L/Pemerintah daerah maupun  Unit Kerja/OPD;\r\n2.  Unit Kerja/OPD memiliki program in house training tahunan; \r\n3. Instansi Pemerintah telah melaksanakan program pelatihan/sertifikasi tersebut dan dibuktikan dengan adanya laporan pelatihan dan bukti perolehan sertifikat keahlian (setiap Unit Kerja/OPD terdapat pegawai yang memiliki sertifikat keahlian); \r\n4. In House Training telah dilaksanakan setidaknya satu kali dalam satu semester oleh masing2  Unit Kerja/OPD serta instruktur harus orang yang telah memiliki sertifikat keahlian; \r\n\r\nB. Kriteria Output:\r\nPelatihan dan in house training untuk meningkatkan kompetensi telah dilakukan untuk setiap tingkatan risiko:\r\n1. Strategis K/L/D untuk Eselon I adalah < 50% pejabat;\r\n2. Strategis  Unit Eselon I/OPD untuk Eselon II adalah < 50% pejabat;\r\n3. Operasional  Unit Eselon I/OPD untuk Eselon III ke atas sampai dengan staf adalah < 50% pejabat dan staff di level ini.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(51,11,'A','Seluruh pegawai telah memiliki pemahaman terkait manajemen risiko','100% pegawai sampel menunjukan kesadaran/keaktifan dalam penerapan MR','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(52,11,'B','Sebagian besar pegawai telah memiliki pemahaman terkait manajemen risiko','70-99% pegawai sampel menunjukan kesadaran/keaktifan dalam penerapan MR','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(53,11,'C','Sebagian pegawai telah memiliki pemahaman terkait manajemen risiko','50% - 70% pegawai sampel menunjukan kesadaran/keaktifan dalam penerapan MR','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(54,11,'D','Sebagian kecil pegawai telah memiliki pemahaman terkait manajemen risiko','20% - 49% pegawai sampel menunjukan kesadaran/keaktifan dalam penerapan MR','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(55,11,'E','Beberapa pegawai telah memiliki kesadaran pemahaman terkait manajemen risiko','< 20% pegawai sampel menunjukan kesadaran/keaktifan dalam penerapan MR','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(56,12,'A','APIP telah menjadi unit yang terus belajar baik dari dalam maupun dari luar organisasi untuk perbaikan berkelanjutan','Mengikuti syarat Level 5 Kapabilitas APIP (Optimizing)','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(57,12,'B','APIP telah mengintegrasikan semua informasi di seluruh organisasi untuk memperbaiki tata kelola dan manajemen risiko','Mengikuti syarat Level 4 Kapabilitas APIP (Managed)','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(58,12,'C','Praktik profesional dan audit internal telah ditetapkan secara seragam','Mengikuti syarat Level 3 Kapabilitas APIP (Integrated)','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(59,12,'D','Proses audit dilakukan secara tetap (rutin) dan berulang','Mengikuti syarat Level 2 Kapabilitas APIP (Infrastructure)','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(60,12,'E','Tidak ada praktik yang tetap, tidak ada kapabilitas yang berulang dan tergantung pada kinerja individu','Mengikuti syarat Level 1 Kapabilitas APIP (Initial)','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(61,13,'A','Pelaksanaan hubungan kerja yang baik dengan mitra kerjasama organisasi menghasilkan efektivitas pencapaian tujuan organisasi dan efisiensi penggunaan sumberdaya masing-masing instansi','Pimpinan organisasi telah menjalin hubungan kerja yang baik dengan instansi lain melalui pembagian peran dan ukuran kinerja yang diharapkan dapat saling mendukung kepada tujuan masing-masing. Pembagian peran mendukung pimpinan untuk mengoptimalkan sumber daya yang ada untuk melaksanakan kegiatan sesuai lingkupnya.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(62,13,'B','Pelaksanaan kebijakan kerjasama organisasi dievaluasi secara berkala','Organisasi melakukan evaluasi atas kebijakan/prosedur pelaksanaan kerjasama dan mekanisme kerja antar unit/organisasi/mitra kerja beserta implementasinya dengan ketentuan sebagai berikut:\r\na. Telah dilaksanakan evaluasi berkala; \r\nb. Evaluasi dilaksanakan untuk menangani hambatan koordinasi/kerjasama;\r\nc. Tindak lanjut atas hasil evaluasi  telah dilaksanakan dengan pembaharuan kebijakan/perubahan pola kerjasama yang diperlukan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(63,13,'C','Masing-masing pihak melaksanakan kegiatan sesuai dengan lingkup kewenangan masing-masing sesuai kebijakan dan ukuran kinerja yang ditetapkan','Organisasi melaksanakan komunikasi, koordinasi, pertukaran data dan informasi dengan unit/organisasi/mitra kerja sesuai dengan kebijakan/prosedur dan kebutuhan dalam rangka pencapaian tujuan organisasi.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(64,13,'D','Pubilkasi kebijakan kerjasama organisasi kepada para pihak yang berkepentingan (antara lain subjek, objek, dan penerima manfaat kerjasama)','Kebijakan/prosedur yang mengatur pelaksanaan kerjasama dan mekanisme kerja antar unit/organisasi/mitra kerja telah dikomunikasikan dan dipahami oleh pihak yang berkepentingan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(65,13,'E','Pimpinan organisasi menetapkan mekanisme hubungan kerja/tata cara kerjasama dengan instansi lain','Adanya kebijakan/prosedur yang mengatur pelaksanaan kerjasama dan mekanisme kerja antar unit/organisasi/mitra kerja dalam upaya pencapaian tujuan organisasi. Kebijakan/prosedur tersebut antara lain memuat:\r\n- lingkup dan hasil kerjasama yang diharapkan;\r\n- alur komunikasi dan koordinasi;\r\n- wewenang, tugas, fungsi, hak, dan kewajiban masing-masing pihak;\r\n- ukuran hasil kerjasama dalam rangka mencapai tujuan organisasi masing-masing.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(66,14,'A','Instansi Pemerintah telah memiliki kebijakan pengelolaan risiko terkait kemitraan, penerapannya telah terintegrasi dengan proses bisnis Instansi Pemerintah, telah direviu secara berkala dan dijadikan bahan pembelajaran','A. Instansi Pemerintah telah memiliki kebijakan pengelolaan risiko terkait kemitraan, telah dilakukan reviu secara berkala dan hasil reviu dijadikan media pembelajaran.\r\nB. Kriteria implementasi adalah sebagai berikut: \r\n1. Terintegrasi apabila penerapan manajemen risiko: \r\na. Telah menyatu dalam proses perencanaan kegiatan kemitraan;\r\nb. Manajemen risiko diterapkan diseluruh kegiatan kemitraan;\r\nc. Dirancang untuk mengelola seluruh risiko yang muncul\r\nd. Menginkorporasikan hasil dari manajemen risiko kedalam dokumen kinerja dan pengambilan keputusan.\r\n2. Kriteria memadai apabila penerapan manajemen risiko telah dilakukan terhadap semua kemitraan yang memiliki peran yang penting dalam organisasi.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(67,14,'B','Instansi Pemerintah telah memiliki kebijakan pengelolaan risiko terkait kemitraan dan penerapannya telah terintegrasi dengan proses bisnis Instansi Pemerintah','A. Instansi Pemerintah telah memiliki kebijakan pengelolaan risiko terkait kemitraan.\r\nB. Kriteria implementasi adalah sebagai berikut: \r\n1. Terintegrasi apabila penerapan manajemen risiko: \r\na. Telah menyatu dalam proses perencanaan kegiatan kemitraan;\r\nb. Manajemen risiko diterapkan diseluruh kegiatan kemitraan;\r\nc. Dirancang untuk mengelola seluruh risiko yang muncul\r\nd. Menginkorporasikan hasil dari manajemen risiko kedalam dokumen kinerja dan pengambilan keputusan.\r\n2. Kriteria memadai apabila penerapan manajemen risiko telah dilakukan terhadap semua kemitraan yang memiliki peran yang penting dalam organisasi.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(68,14,'C','Instansi Pemerintah telah memiliki kebijakan pengelolaan risiko terkait kemitraan dan telah diterapkan dengan memadai','A. Instansi Pemerintah telah memiliki kebijakan pengelolaan risiko terkait kemitraan.\r\nB. Kriteria implementasi secara memadai apabila penerapan manajemen risiko telah dilakukan terhadap semua kemitraan yang memiliki peran yang penting dalam organisasi.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(69,14,'D','Instansi Pemerintah telah memiliki kebijakan pengelolaan risiko terkait kemitraan namun belum diterapkan dengan memadai','A. Instansi Pemerintah telah memiliki kebijakan pengelolaan risiko terkait kemitraan.\r\nB. Kriteria implementasi secara tidak memadai apabila sebagian dari kemitraan utama (yang memiliki peran penting terhadap organisasi) yang telah menerapkan manajemen risiko.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(70,14,'E','Instansi Pemerintah telah memiliki kebijakan pengelolaan risiko terkait kemitraan namun belum diterapkan sama sekali','Sudah Jelas','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(71,15,'A','K/L/D telah memiliki Kebijakan Manajemen Risiko yang memadai, terintegrasi serta telah direviu secara berkala','Kebijakan Manajemen Risiko memiliki kriteria memadai dan dalam kebijakan tersebut telah menjelaskan bahwa: \r\n1. Penerapan manajemen risiko oleh Instansi Pemerintah telah menyatu/menjadi pertimbangan dalam proses perencanaan (perumusan target dan strategi pencapaian tujuan Instansi Pemerintah), \r\n2. Manajemen risiko diterapkan diseluruh level organisasi\r\n3. Manajemen risiko dirancang untuk mengelola seluruh risiko yang muncul\r\n4. Menginkorporasikan hasil dari manajemen risiko kedalam dokumen kinerja dan pengambilan keputusan\r\n5. Kebijakan tersebut telah direviu secara berkala','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(72,15,'B','K/L/D telah memiliki Kebijakan Manajemen Risiko yang memadai dan terintegrasi','Terintegrasi berarti bahwa Kebijakan Manajemen Risiko memiliki kriteria memadai dan dalam kebijakan tersebut telah menjelaskan bahwa: \r\n1. Penerapan manajemen risiko oleh Instansi Pemerintah telah menyatu/menjadi pertimbangan dalam proses perencanaan (perumusan target dan strategi pencapaian tujuan Instansi Pemerintah), \r\n2. Manajemen risiko diterapkan diseluruh level organisasi\r\n3. Manajemen risiko dirancang untuk mengelola seluruh risiko yang muncul\r\n4. Menginkorporasikan hasil dari manajemen risiko kedalam dokumen kinerja dan pengambilan keputusan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(73,15,'C','K/L/D telah memiliki Kebijakan Manajemen Risiko yang memadai','Memadai apabila Kebijakan Manajemen Risiko yang dibuat telah memuat:\r\n1. Penetapan konteks manajemen risiko (konteks risiko strategis dan Operasional)\r\n2. Identifikasi risiko setidaknya memuat penyebab risiko, dampak risiko, pihak yang terkena dampak\r\n3. Analisis risiko setidaknya memuat metode prioritisasi risiko\r\n4. Penetapan kriteria penilaian risiko (kriteria dampak, kriteria kemungkinan, dan skala nilai risiko);\r\n5. Penetapan struktur manajemen risiko dan alur pertanggungjawaban;\r\n6. Penetapan risk appetite/selera risiko\r\n7. Gambaran proses manajemen risiko.\r\n9. Pembangunan budaya risiko','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(74,15,'D','K/L/D telah memiliki Kebijakan Manajemen Risiko namun belum memadai','Belum memadai apabila K/L/D telah memiliki kebijakan terkait manajemen risiko namun belum memenuhi seluruh kriteria kebijakan yang memadai (hanya memenuhi beberapa parameter yang ada dalam kriteria memadai)','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(75,15,'E','K/L/D telah memiliki Kebijakan Manajemen Risiko namun sama sekali belum memuat persyaratan dalam kriteria memadai','Sudah Jelas','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(76,16,'A','Kualitas identifikasi risiko dan register risiko memadai, serta telah mengidentifikasi peluang','Kualitas Identifikasi Risiko dan Risk Register yang memadai bila:\r\n1. Proses identifikasi risiko menghasilkan risiko utama dan peluang yang bisa diambil;\r\n2. Seluruh sasaran strategis K/L/D, sasaran strategis unit kerja serta program dan kegiatan yang telah ditetapkan dalam penetapan konteks telah diidentifikasi risikonya;\r\n3. Pihak yang terlibat setidakya seluruh pegawai unit kerja yang benar-benar memahami proses bisnis organisasi;\r\n4. Proses identifikasi telah sesuai dengan kebijakan yang dibuat;\r\n5. Risk register setidaknya memuat hal berikut: a. uraian tujuan/sasaran strategis/kegiatan, b. Indikator  tujuan/sasaran strategis/kegiatan, c. Uraian Risiko, d. Pemilik risiko, e. Uraian dan sumber penyebab, f. Uraian dan pihak yang terdampak;\r\n6. Pernyataan risiko, RTP, penyebab secara umum jelas/dapat dipahami (>90% sampling).','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(77,16,'B','Kualitas identifikasi risiko dan register risiko memadai','Kualitas Identifikasi Risiko dan Risk Register yang memadai bila:\r\n1. Proses identifikasi risiko menghasilkan risiko utama;\r\n2. Seluruh program dan kegiatan serta sasaran statregis unit kerja yang telah ditetapkan dalam penetapan konteks telah diidentifikasi risikonya;\r\n3. Pihak yang terlibat setidakya seluruh pegawai unit kerja yang benar-benar memahami proses bisnis organisasi;\r\n4. Proses identifikasi telah sesuai dengan kebijakan yang dibuat;\r\n5. Risk register setidaknya memuat hal berikut: a. uraian tujuan/sasaran strategis/kegiatan, b. Indikator  tujuan/sasaran strategis/kegiatan, c. Uraian Risiko, d. Pemilik risiko, e. Uraian dan sumber penyebab, f. Uraian dan pihak yang terdampak;\r\n6. Pernyataan risiko, RTP penyebab, secara umum jelas/dapat dipahami (70%-90% sampling).','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(78,16,'C','Kualitas identifikasi risiko dan register risiko cukup memadai','Kualitas Identifikasi Risiko dan Risk Register cukup memadai bila:\r\n1. Proses identifikasi risiko menghasilkan risiko utama;\r\n2. Seluruh program dan kegiatan yang telah ditetapkan dalam penetapan konteks telah diidentifikasi risikonya;\r\n3. Pihak yang terlibat setidakya 2/3 pegawai unit kerja yang benar-benar memahami proses bisnis organisasi;\r\n4. Proses identifikasi telah sesuai dengan kebijakan yang dibuat;\r\n5. Risk register setidaknya memuat hal berikut: a. uraian tujuan/sasaran strategis/kegiatan, b. Indikator  tujuan/sasaran strategis/kegiatan, c. Uraian Risiko, d. Pemilik risiko, e. Uraian dan sumber penyebab, f. Uraian dan pihak yang terdampak;\r\n6. Pernyataan risiko, RTP penyebab sebagia besar jelas/dapat dipahami (50%-70% sampling).','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(79,16,'D','Kualitas identifikasi risiko dan register risiko belum memadai','Kualitas Identifikasi Risiko dan Risk Register belum memadai bila:\r\n1. Proses identifikasi risiko menghasilkan daftar risiko\r\n2. Belum seluruh program dan kegiatan yang telah ditetapkan dalam penetapan konteks telah diidentifikasi risikonya;\r\n3. Pihak yang terlibat kurang dari 2/3 pegawai unit kerja yang benar-benar memahami proses bisnis organisasi;\r\n4. Proses identifikasi belum sesuai dengan kebijakan yang dibuat, baru sebatas 1-2 proses yang sesuai dengan kebijakannya;\r\n5. Risk register yang dibuat belum sesuai dengan kriteria memadai yaitu masih ada hal-hal sebagai berikut ini yang tidak dicantumkan:  a. uraian tujuan/sasaran strategis/kegiatan, b. Indikator  tujuan/sasaran strategis/kegiatan, c. Uraian Risiko, d. Pemilik risiko, e. Uraian dan sumber penyebab, f. Uraian dan pihak yang terdampak\r\n6. Pernyataan risiko, RTP penyebab secara umum kurang jelas/dapat dipahami (<50%sampling).','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(80,16,'E','Register risiko telah disusun','Sudah Jelas','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(81,17,'A','Proses manajemen risiko mendukung inovasi, diidentifikasi untuk memaksimalkan peluang dan dijadikan bahan pembelajaran','Proses manajemen risiko telah terintegrasi dengan proses bisnis utama dari unit kerja terkait dan menjadi pertimbangan dalam proses perencaan strategis K/L/D dan Unit kerja Eselon I/II/OPD maupun dalam proses perencanaan operasional unit kerja Eselon I/II/OPD. Proses manajemen risiko juga dilakukan untuk mengidentifikasi dan memaksimalkan peluang-peluang yang ada serta mendorong adanya inovasi-inovasi. Disamping itu, hasil dari proses manajemen risiko menjadi bahan pembelajaran dalam pengambilan keputusan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(82,17,'B','Proses manajemen risiko telah diterapkan secara konsisten, terintegrasi dengan proses bisnis dan proses perencanaan tingkat operasional unit kerja, strategis unit kerja, dan strategis K/L/D','Proses manajemen risiko telah melekat (terintegrasi) dengan proses bisnis utama dari unit kerja terkait dan menjadi pertimbangan dalam proses perencanaan strategis K/L/D, strategis unit kerja, dan operasional unit kerja','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(83,17,'C','Proses manajemen risiko telah diterapkan secara konsisten, terintegrasi dengan proses bisnis dan proses perencanaan tingkat operasional unit kerja dan strategis unit kerja','Proses manajemen risiko telah terintegrasi dengan proses bisnis utama dari unit kerja terkait dan menjadi pertimbangan dalam proses perencanaan pada strategis unit kerja dan pada operasional unit kerja','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(84,17,'D','Proses manajemen risiko telah terintegrasi dengan dengan proses bisnis dan proses perencanaan tingkat operasional unit kerja serta telah diterapkan secara konsisten','Proses manajemen risiko telah terintegrasi dengan proses bisnis utama dari unit kerja terkait dan menjadi pertimbangan dalam proses perencaan pada operasional unit kerja serta implementasi dari proses manajemen risiko ini telah dilakukan secara konsisten oleh unit kerja.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(85,17,'E','Proses manajemen risiko mulai dihubungkan dengan dengan proses bisnis dan proses perencanaan tingkat operasional unit kerja namun belum diterapkan secara konsisten','Proses manajemen risiko mulai dihubungkan dengan proses bisnis utama dari unit kerja terkait dan mulai diterapkan dalam proses perencaan unit kerja. Namun demikian implementasi dari proses manajemen risiko ini belum dilakukan secara konsisten oleh unit kerja.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(86,18,'A','Analisis risiko telah dilakukan secara memadai terhadap risiko operasional unit kerja, risiko strategis unit kerja, dan risiko strategis K/L/D','A. Instansi Pemerintah telah melakukan analisis risiko untuk hasil identifikasi risiko di tingkat operasional unit kerja, strategis unit kerja, dan strategis K/L/D secara memadai yaitu:\r\n1. Telah sesuai dengan kebijakan (termasuk selera risiko dan langkah analisis);\r\n2. Kriteria yang digunakan baik dampak maupun probabilitasnya konsisten antara satu unit kerja dengan unit kerja lain;\r\n3. Proses analisis risiko dilaksanakan setidaknya oleh orang2 yang memiliki kompetensi.\r\nB. Hasil dari proses ini telah menghasilkan tren risiko.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(87,18,'B','Analisis risiko telah dilakukan secara memadai terhadap risiko operasional unit kerja dan risiko strategis unit kerja','A. Instansi Pemerintah telah melakukan analisis risiko untuk hasil identifikasi risiko di tingkat operasional unit kerja dan strategis unit kerja secara memadai yaitu:\r\n1. Telah sesuai dengan kebijakan (termasuk selera risiko dan langkah analisis);\r\n2. Kriteria yang digunakan baik dampak maupun probabilitasnya konsisten antara satu unit kerja dengan unit kerja lain;\r\n3. Proses analisis risiko dilaksanakan setidaknya oleh orang2 yang memiliki kompetensi.\r\nB. Hasil dari proses ini telah menghasilkan tren risiko.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(88,18,'C','Analisis risiko telah dilakukan secara memadai terhadap risiko operasional unit kerja','A. Instansi Pemerintah telah melakukan analisis risiko untuk hasil identifikasi risiko di tingkat operasional unit kerja secara memadai yaitu:\r\n1. Telah sesuai dengan kebijakan (termasuk selera risiko dan langkah analisis);\r\n2. Kriteria yang digunakan baik dampak maupun probabilitasnya konsisten antara satu unit kerja dengan unit kerja lain;\r\n3. Proses analisis risiko dilaksanakan setidaknya oleh orang2 yang memiliki kompetensi.\r\nB. Hasil dari proses ini telah menghasilkan tren risiko.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(89,18,'D','Analisis risiko telah dilakukan terhadap seluruh risiko operasional yang teridentifikasi namun belum memadai','Instansi Pemerintah telah melakukan proses analisis risiko terhadap seluruh risiko operasional unit kerja yang telah diidentifikasi. Namun demikian proses analisis risiko belum dikerjakan secara memadai sesuai dengan 3 kriteria sistematis (sebagaimana disebutkan pada kriteria C)','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(90,18,'E','Analisis risiko telah dilakukan terhadap sebagian risiko operasional yang teridentifikasi.','Analisis hanya dilakukan pada sebagian dari keseluruhan risiko yang teridentifikasi','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(91,19,'A','Instansi Pemerintah telah menentukan prioritas risiko pada seluruh risiko operasional unit kerja, strategis unit kerja, strategis K/L/D','1. Instansi Pemerintah telah melakukan evaluasi risiko untuk menentukan prioritas risiko operasional unit kerja, strategis unit kerja, dan strategis K/L/D terhadap seluruh hasil analisis risiko yang telah dilakukan;\r\n2. Proses evaluasi risiko telah didokumentasikan.\r\n3. Evaluasi risiko dilakukan sesuai dengan kebijakan kriteria risiko yang telah ditetapkan sebelumnya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(92,19,'B','Instansi Pemerintah telah menentukan prioritas risiko pada seluruh risiko operasional unit kerja dan strategis unit kerja','1. Instansi Pemerintah telah melakukan evaluasi risiko untuk menentukan prioritas risiko operasional unit kerja dan strategis unit kerja terhadap seluruh hasil analisis risiko yang telah dilakukan;\r\n2. Proses evaluasi risiko telah didokumentasikan.\r\n3. Evaluasi risiko dilakukan sesuai dengan kebijakan kriteria risiko yang telah ditetapkan sebelumnya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(93,19,'C','Instansi Pemerintah telah menentukan prioritas risiko pada seluruh risiko operasional unit kerja dan sebagian risiko strategis unit kerja','1. Instansi Pemerintah telah melakukan evaluasi risiko untuk menentukan prioritas seluruh risiko operasional unit kerja dan sebagian risiko strategis unit kerja terhadap seluruh hasil analisis risiko yang telah dilakukan;\r\n2. Proses evaluasi risiko telah didokumentasikan.\r\n3. Evaluasi risiko dilakukan sesuai dengan kebijakan kriteria risiko yang telah ditetapkan sebelumnya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(94,19,'D','Instansi Pemerintah telah menentukan prioritas risiko pada seluruh risiko operasional unit kerja','1. Instansi Pemerintah telah melakukan evaluasi risiko untuk menentukan prioritas risiko operasional unit kerja serta telah mendokumentasikan proses evaluasi risiko tersebut evaluasi risiko telah dilakukan terhadap seluruh hasil analis risiko yang telah dilakukan.\r\n2. Evaluasi risiko yang dilakukan belum sesuai dengan kebijakan kriteria risiko yang telah ditetapkan sebelumnya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(95,19,'E','Instansi Pemerintah telah menentukan prioritas risiko pada sebagian risiko operasional unit kerja','1. Instansi Pemerintah telah melakukan evaluasi risiko untuk menentukan prioritas risiko operasional unit kerja serta telah mendokumentasikan proses evaluasi risiko tersebut namun demikian evaluasi risiko belum dilakukan terhadap seluruh hasil analis risiko yang telah dilakukan.\r\n2. Evaluasi risiko yang dilakukan belum sesuai dengan kebijakan kriteria risiko yang telah ditetapkan sebelumnya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(96,20,'A','Instansi Pemerintah telah menentukan rencana tindak pengendalian terhadap risiko operasional unit kerja, strategis unit kerja, dan strategis K/L/D secara memadai','>60%  RTP terhadap risiko operasional unit kerja, strategis unit kerja, dan strategis K/L/D yang disusun  (sampling) telah relevan dengan tujuan yang ingin dicapai, jelas target waktu, penanggung jawab, ukuran pelaksanaan, secara substansi dinilai dapat mengurangi dampak/menghilangkan penyebab,realistis.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(97,20,'B','Instansi Pemerintah telah menentukan rencana tindak pengendalian terhadap risiko operasional unit kerja dan strategis unit kerja secara memadai','>60% RTP terhadap risiko operasional unit kerja dan strategis unit kerja yang disusun  (sampling) telah relevan dengan tujuan yang ingin dicapai, jelas target waktu, penanggung jawab, ukuran pelaksanaan, secara substansi dinilai dapat mengurangi dampak/menghilangkan penyebab,realistis.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(98,20,'C','Instansi Pemerintah telah menentukan rencana tindak pengendalian terhadap seluruh risiko operasional unit kerja dan sebagian risiko strategis unit kerja yang telah diprioritaskan','>60% RTP terhadap risiko operasional unit kerja dan <60% RTP terhadap risiko strategis unit kerja yang disusun  (sampling) telah relevan dengan tujuan yang ingin dicapai, jelas target waktu, penanggung jawab, ukuran pelaksanaan, secara substansi dinilai dapat mengurangi dampak/menghilangkan penyebab,realistis.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(99,20,'D','Instansi Pemerintah telah menentukan rencana tindak pengendalian terhadap seluruh risiko operasional unit kerja yang telah diprioritaskan','>60% RTP terhadap risiko operasional unit kerja yang disusun  (sampling) telah relevan dengan tujuan yang ingin dicapai, jelas target waktu, penanggung jawab, ukuran pelaksanaan, secara substansi dinilai dapat mengurangi dampak/menghilangkan penyebab,realistis.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(100,20,'E','Instansi Pemerintah telah menentukan rencana tindak pengendalian terhadap sebagian risiko operasional unit kerja yang telah diprioritaskan','<60% RTP terhadap risiko operasional unit kerja yang disusun  (sampling) telah relevan dengan tujuan yang ingin dicapai, jelas target waktu, penanggung jawab, ukuran pelaksanaan, secara substansi dinilai dapat mengurangi dampak/menghilangkan penyebab,realistis.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(101,21,'A','Tindak pengendalian terhadap seluruh risiko operasional unit kerja, risiko strategis unit kerja, dan risiko strategis K/L/D telah diimplementasikan','>60% RTP terhadap risiko operasional unit kerja, strategis unit kerja, dan strategis K/L/D (sampling) yang direncanakan telah diimplementasikan dan didukung oleh sumber daya yang dibutuhkan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(102,21,'B','Tindak pengendalian terhadap seluruh risiko operasional unit kerja dan risiko strategis unit kerja telah diimplementasikan','>60% RTP terhadap risiko operasional unit kerja dan strategis unit kerja (sampling) yang direncanakan telah diimplementasikan dan didukung oleh sumber daya yang dibutuhkan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(103,21,'C','Tindak pengendalian terhadap seluruh risiko operasional unit kerja dan sebagian risiko strategis unit kerja telah diimplementasikan','>60% RTP terhadap risiko operasional unit kerja dan <60% RTP terhadap risiko strategis unit kerja (sampling) yang direncanakan telah diimplementasikan dan didukung oleh sumber daya yang dibutuhkan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(104,21,'D','Tindak pengendalian terhadap seluruh risiko operasional unit kerja telah diimplementasikan','>60% RTP terhadap risiko operasional unit kerja (sampling) yang direncanakan telah diimplementasikan dan didukung oleh sumber daya yang dibutuhkan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(105,21,'E','Tindak pengendalian terhadap sebagian risiko operasional unit kerja telah diimplementasikan','<60% RTP terhadap risiko operasional unit kerja (sampling) yang direncanakan telah diimplementasikan dan didukung oleh sumber daya yang dibutuhkan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(106,22,'A','Tindak pengendalian telah efektif menurunkan risiko operasional unit kerja, strategis unit kerja, dan strategis K/L/D','RTP untuk risiko tingkat operasional unit kerja, tingkat strategis unit kerja, dan tingkat strategis K/L/D mampu menurunkan level risiko sebesar >60%.\r\nMisalnya terdapat  20 risiko yang yang perlu ditangani (diluar batas risk tolerance), dari 20 risiko tersebut ternyata terdapat 5 kejadian risiko yang mana 2 kejadian masih dalam batas risk tolerance sedangkan 3 kejadian diluar batas risk tolerance. Maka efektivitas penangan risiko dihitung dengan cara ((20-3)/20)X100%=95%.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(107,22,'B','Tindak pengendalian telah efektif menurunkan risiko operasional unit kerja dan strategis unit kerja','RTP untuk risiko tingkat operasional unit kerja dan tingkat strategis unit kerja mampu menurunkan level risiko sebesar >60%.\r\nMisalnya terdapat  20 risiko yang yang perlu ditangani (diluar batas risk tolerance), dari 20 risiko tersebut ternyata terdapat 5 kejadian risiko yang mana 2 kejadian masih dalam batas risk tolerance sedangkan 3 kejadian diluar batas risk tolerance. Maka efektivitas penangan risiko dihitung dengan cara ((20-3)/20)X100%=95%.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(108,22,'C','Tindak pengendalian efektif menurunkan seluruh risiko operasional unit kerja dan sebagian risiko strategis unit kerja','RTP untuk risiko tingkat operasional unit kerja mampu menurunkan level risiko sebesar >60% dan risiko tingkat operasional unit kerja mampu menurunkan level risiko sebesar >60%.\r\nMisalnya terdapat  20 risiko yang yang perlu ditangani (diluar batas risk tolerance), dari 20 risiko tersebut ternyata terdapat 5 kejadian risiko yang mana 2 kejadian masih dalam batas risk tolerance sedangkan 3 kejadian diluar batas risk tolerance. Maka efektivitas penangan risiko dihitung dengan cara ((20-3)/20)X100%=95%.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(109,22,'D','Tindak pengendalian efektif menurunkan seluruh risiko operasional unit kerja','RTP untuk risiko operasional unit kerja mampu menurunkan level risiko sebesar >60%','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(110,22,'E','Tindak pengendalian efektif menurunkan sebagian risiko operasional unit kerja','RTP untuk risiko operasional unit kerja mampu menurunkan level risiko sebesar <60%.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(111,23,'A','Pelaksanaan reviu kinerja mendukung pencapaian kinerja organisasi','a. Terdapat perbaikan yang berkelanjutan atas kinerja organisasi, unit kerja, kegiatan, dan pegawai sebagai akibat pelaksanaan reviu kinerja,\r\nb. Reviu kinerja memungkinkan penilaian terhadap tolok ukur kinerja seluruh level pimpinan dan pegawai dalam mendukung pencapaian tujuan organisasi.\r\nc. Hasil reviu kinerja digunakan pimpinan organisasi dalam penetapan kebijakan pelaksanaan kegiatan, pengalokasikan sumber daya, dan pertimbangan dalam penilaian kinerja secara individual.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(112,23,'B','Kebijakan dan pelaksanaan reviu kinerja organisasi oleh masing-masing jenjang pimpinan telah dievaluasi secara berkala','K/L/D melakukan evaluasi atas kebijakan/prosedur reviu kinerja dengan ketentuan sebagai berikut:\r\n1. Dilaksanakan secara berkala;\r\n2. Dilaksanakan untuk menangani residual risk; dan\r\n3. Tindak lanjut atas hasil evaluasi  telah dilaksanakan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(113,23,'C','Reviu kinerja organisasi dilaksanakan dan didokumentasikan dengan baik untuk dibandingkan pengaruhnya terhadap capaian kinerja periode berikutnya','a. Reviu kinerja telah dilaksanakan secara berjenjang dengan didasarkan pada tolok ukur kinerja yang ditetapkan,\r\nb. Rekomendasi/arahan pimpinan yang diberikan relevan dengan kendala pencapaian kinerja yang ditemukan dan tepat sasaran,\r\nc. Rekomendasi /arahan pimpinan dilaksanakan,\r\nd. Perbaikan capaian kinerja dapat ditunjukan sebagai akibat pelaksanaan rekomendasi perbaikan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(114,23,'D','Kewajiban pelaksanaan reviu kinerja diketahui oleh seluruh pimpinan unit dan pegawai','Pimpinan unit dan pegawai telah mengetahui target kinerja yang harus dicapai dan seluruh kegiatan yang dilaksanakan memiliki tolok ukur kinerja dan wajib direviu secara berkala sesuai jenjang tanggung jawabnya.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(115,23,'E','Pimpinan organisasi dan jajaran di bawahnya secara berjenjang memiliki tanggungjawab/kewajiban untuk melaksanakan reviu kinerja secara berkala','Adanya kebijakan/prosedur terkait pelaksanaan reviu kinerja organisasi, unit kerja, kegiatan, dan pegawai.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(116,24,'A','Pembinaan SDM organisasi telah diperbaiki secara berkelanjutan dan secara optimal mampu mendukung pencapaian tujuan organisasi','- Pembinaan SDM telah mampu menyesuaikan dengan perubahan lingkungan strategis\r\n- Pembinaan SDM telah berhasil meningkatkan kinerja yang memberikan dampak bagi pencapaian tujuan organisasi\r\n- Keberhasilan pencapaian kinerja organisasi dapat dihubungkan dengan pembinaan SDM-nya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(117,24,'B','Kebijakan dan implementasi terkait pembinaan SDM organisasi telah dievaluasi sehingga dapat diketahui efektivitasnya','Kebijakan dan implementasi telah dievaluasi dengan ketentuan:\r\n- Berkala \r\n- Terdokumentasi\r\n- Dilakukan untuk menangani residual risk\r\n- Hasil evaluasi telah ditindak lanjuti \r\n- Perbaikan telah menghasilkan kinerja yang lebih baik','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(118,24,'C','Pembinaan SDM telah dilaksanakan sesuai kebijakan/prosedur yang ditetapkan organisasi','- Pembinaan SDM dilakukan sebagai upaya untuk mencapai visi, misi, tujuan dan sasaran organisasi\r\n- Pembinaan SDM dilakukan sesuai dengan perencanaan yang disusun\r\n- Perencanaan pembinaan SDM disusun dengan mempertimbangkan gap kompetensi pegawai dan penugasan yang akan dilaksanakannya\r\n- Pembinaan SDM dilakukan sebagai upaya untuk menangani risiko yang disebabkan kelemahan SDM/Man','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(119,24,'D','Kebijakan terkait pembinaan SDM telah dikomunikasikan dan dipahami oleh pihak yang berkepentingan','- Kebijakan telah dipahami oleh penanggungjawab pengelolaan SDM\r\n- Kebijakan telah dikomunikasikan kepada pimpinan (struktural) dan pegawai','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(120,24,'E','Terdapat kebijakan yang mengatur pembinaan SDM untuk mendukung pelaksanaan tugas dan fungsi organisasi','Kebijakan telah mengatur:\r\n- Prosedur pendidikan dan pelatihan pegawai\r\n- Rencana pengembangan karir pegawai\r\n- Sistem penilaian kinerja pegawai\r\n- Sistem kompensasi, program kesejahteraan, dan fasilitas pegawai\r\nuntuk seluruh pegawai baik pimpinan maupun staf','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(121,25,'A','Perbaikan terkait pengelolaan sistem informasi organisasi dilakukan secara berkelanjutan.','a. Terdapat sistem pengelolaan sistem informasi yang terintegrasi;\r\nb. Terdapat perbaikan berkelanjutan atas pengelolaan sistem informasi sesuai dengan perubahan lingkungan strategis;\r\nc. Sistem informasi menghasilkan seluruh data yang dibutuhkan untuk pelaporan dan pengambilan keputusan  oleh pimpinan.\r\nc. Pengelolaan sistem informasi telah mendukung pencapaian tujuan organisasi.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(122,25,'B','Kebijakan pengendalian atas pengelolaan sistem informasi organisasi telah dievaluasi secara berkala.','K/L/D melakukan evaluasi atas K/SOP terkait pengelolaan sistem informasi beserta implementasinya dengan ketentuan sebagai berikut:\r\n1. Telah dilaksanakan evaluasi berkala;\r\n2. Evaluasi dilaksanakan untuk menangani residual risk;\r\n3. Tindak lanjut atas hasil evaluasi  telah dilaksanakan.\r\n4. Perbaikan menghasilkan perbaikan kualitas atas informasi yang dihasilkan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(123,25,'C','Kebijakan pengelolaan sistem informasi organisasi digunakan dalam analisis kebutuhan dukungan sistem informasi, kemanfaatan sistem informasi existing, serta struktur pengelola dan pengguna sistem informasi beserta wewenang dan tanggungjawabnya.','Seluruh kebijakan/SOP tentang pengelolaan sistem informasi telah diimplementasikan, antara lain:\r\na. Sistem informasi yang digunakan telah dianalisis kemanfaatannya bagi pencapaian tujuan organisasi;\r\nb. Aset-aset yang berhubungan dengan teknologi informasi telah dipetakan dan dicatat serta dianalisis kebutuhannya;\r\nc. Struktur organisasi pengelola sistem informasi telah menjalankan proses bisnis yang diatur dengan SOP;\r\nd. Kewenangan dan tanggung jawab pengelola sistem informasi dan pengguna sistem informasi dijalankan sesuai dengan perannya masing-masing.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(124,25,'D','Unit pengelola sistem informasi organisasi dan pengguna mengetahui kebijakan pengelolaan sistem informasi.','Unit pengelola dan pengguna sistem informasi memahami prosedur pengelolaan sistem informasi dan tanggung jawab sesuai dengan perannya masing-masing.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(125,25,'E','Pimpinan organisasi menetapkan kebijakan/grand design pengelolaan sistem informasi.','Adanya kebijakan pengelolaan sistem informasi yang antara lain mempertimbangkan:\r\na. Risiko penggunaan sistem informasi;\r\nb. Prosedur otorisasi atas sistem informasi;\r\nc. Penetapan aset teknologi informasi yang perlu dikelola dan rencana penyusunan kebijakan dan prosedur teknologi informasi;\r\nd. Penetapan struktur organisasi untuk mengelola sistem informasi (termasuk program pengamanan);\r\ne. Kebijakan dan prosedur pemisahan fungsi dalam pengelolaan sistem informasi; dan\r\nf. Pedoman rencana kontinjensi (contingency plan).','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(126,26,'A','Perbaikan berkelanjutan atas pengelolaan aset organisasi','Perbaikan berkelanjutan atas pengelolaan aset didukung dengan sistem pengendalian atas aset yang terintegrasi dan menghasilkan aset yang tersedia secara optimal dalam mendukung kinerja organisasi; antara lain ditunjukan dengan kondisi:\r\na. tidak terdapat aset dengan kondisi rusak baik ringan maupun berat;\r\nb. tidak terdapat keluhan atas penggunaan aset oleh pengguna;\r\nc. tidak terdapat aset pribadi yang digunakan untuk keperluan organisasi akibat keterbatasan aset.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(127,26,'B','Kebijakan/prosedur pengelolaan atas aset organisasi termasuk pengamanan fisik atas aset dievaluasi secara berkala','K/L/D melakukan evaluasi atas K/SOP terkait pengendalian fisik atas aset beserta implementasinya dengan ketentuan sebagai berikut:\r\na. Telah dilaksanakan evaluasi berkala;\r\nb. Evaluasi dilaksanakan untuk menangani residual risk;\r\nc. Tindak lanjut atas hasil evaluasi  telah dilaksanakan.\r\nd. Evaluasi meningkatkan kepuasan penggunaan aset oleh pengguna aset dalam mendukung pencapaian kinerja.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(128,26,'C','Kebijakan/prosedur pengelolaan atas aset organisasi termasuk pengamanan fisik atas aset diimplementasikan secara memadai','a. Kebijakan pengelolaan aset diimplementasikan, antara lain:\r\n- Aset yang berisiko hilang, dicuri, rusak, digunakan tanpa hak secara fisik diamankan dan akses ke aset tersebut dikendalikan.\r\n- Aset secara periodik dihitung dan dibandingkan dengan catatan pengendalian; setiap perbedaan diperiksa secara teliti.\r\n- Identitas aset dilekatkan pada masing-masing fisik aset.\r\n- Persediaan dan perlengkapan disimpan di tempat yang diamankan secara fisik dan dilindungi dari kerusakan.\r\nb. Observasi dilakukan secara rutin oleh pengelola aset untuk melihat secara langsung kegiatan pengamanan dan penggunaan aset sudah sesuai dengan kebijakan/SOP yang ditetapkan.\r\nc. Kejadian dalam penggunaan aset yang menimbulkan risiko rusak segera ditangani dengan pengamanan dan perbaikan  yang diperlukan agar aset dapat segera digunakan kembali.\r\nd. Sebagian besar pengguna aset dapat memperoleh manfaat atas keberadaan aset dalam mendukung kinerja organsisasi.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(129,26,'D','Kebijakan pengelolaan aset organisasi dipahami oleh pengelola aset dan pengguna aset','Kebijakan/SOP tentang pengelolaan aset disampaikan kepada seluruh pejabat dan sebagian besar pegawai serta pihak lain yang berkepentingan (eksternal).','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(130,26,'E','Pimpinan organisasi menetapkan kebijakan/prosedur pengelolaan BMN/D','a. Adanya kebijakan mengenai aset yang memuat antara lain perencanaan kebutuhan dan penganggaran, pengadaan, pengunaan, pemanfaatan, pengamanan, dan pemeliharaan, penilaian, pemindahtanganan, pemusnahan, penghapusan, penatausahaan, dan pembinaan pengawasan dan pengendalian.\r\nb. Kebijakan pengelolaan aset mempertimbangkan identifikasi, pengamanan, dan rencana pemulihan setelah bencana (disaster recovery plan).','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(131,27,'A','Perbaikan berkelanjutan atas penetapan dan reviu atas indikator dan ukuran kinerja organisasi','Perbaikan berkelanjutan atas kebijakan/prosedur penetapan indikator dan ukuran kinerja menghasilkan pencapaian tujuan organisasi.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(132,27,'B','Kebijakan/prosedur penetapan dan reviu atas indikator dan ukuran kinerja organisasi dievaluasi secara berkala','a.  K/L/D telah melaksanakan reviu secara berkala terhadap kebijakan/prosedur penetapan indikator dan ukuran kinerja dari organisasi, unit kerja, kegiatan, sampai dengan pegawai.\r\nb. Hasil reviu telah ditindaklanjuti dengan perbaikan perumusan indikator dan ukuran kinerja.\r\nc. Indikator dan ukuran kinerja yang ditetapkan mencapai kriteria tepat dan andal.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(133,27,'C','Kebijakan/prosedur penetapan dan reviu atas indikator dan ukuran kinerja organisasi dilaksanakan secara memadai.','Indikator dan ukuran kinerja direviu dan divalidasi secara periodik atas ketepatan dan keandalan ukuran dan indikator kinerja.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(134,27,'D','Kebijakan/prosedur penetapan dan reviu atas indikator dan ukuran kinerja organisasi dipahami namun belum sepenuhnya diimplementasikan.','Setiap tingkatan pada organisasi sampai dengan individu telah memahami prosedur penetapan indikator dan ukuran kinerja terutama unit/pegawai yang menjalankan fungsi perencanaan kinerja namun belum sepenuhnya tepat dan andal.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(135,27,'E','Pimpinan organisasi menetapkan kebijakan/prosedur penetapan dan reviu atas indikator dan ukuran kinerja.','Adanya kebijakan/prosedur sebagai pedoman penetapan atas indikator dan ukuran kinerja untuk tingkat unit, kegiatan, sampai dengan individu dan memuat bagaimana pimpinan melaksanaan reviu atas ketepatan indikator dan ukuran kinerjanya.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(136,28,'A','Pemisahan fungsi telah diperbaiki secara berkelanjutan dan secara optimal mampu mendukung pencapaian tujuan organisasi','- Pemisahan fungsi telah mampu menyesuaikan dengan perubahan lingkungan strategis\r\n- Pemisahan fungsi secara efektif mampu memitigasi risiko kolusi dan penyalahgunaan wewenang\r\n- Pemisahan fungsi mampu membuat pelaksanaan program dan kegiatan lebih efektif dalam mencapai tujuan organisasi','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(137,28,'B','Kebijakan dan implementasi terkait pemisahan fungsi dalam proses transaksi dan kejadian telah dievaluasi sehingga dapat diketahui efektivitasnya','Kebijakan dan implementasi telah dievaluasi dengan ketentuan:\r\n- Berkala\r\n- Terdokumentasi\r\n- Dilakukan untuk menangani residual risk\r\n- Hasil evaluasi telah ditindak lanjuti \r\n- Perbaikan telah menghasilkan kinerja yang lebih baik','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(138,28,'C','Pemisahan fungsi dalam proses transaksi dan kejadian telah dilaksanakan sesuai kebijakan/prosedur yang ditetapkan','- Pemisahan fungsi dilaksanakan sesuai ketentuan (struktur organisasi, peraturan/keputusan, SOP, petunjuk teknis/petunjuk pelaksanaan, dan/atau kebijakan lain)\r\n- Pemisahan fungsi dilaksanakan baik pada kegiatan yang terkait dengan keuangan (penerimaan/pengeluaran) maupun kegiatan teknis operasional organisasi\r\n- Pemisahan fungsi dilakukan sebagai upaya untuk menangani risiko yang disebabkan kelemahan alur/prosedur','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(139,28,'D','Kebijakan terkait pemisahan fungsi dalam proses transaksi dan kejadian telah dikomunikasikan dan dipahami oleh pihak yang berkepentingan','- Kebijakan telah dipahami oleh penanggungjawab pengelolaan keuangan/kegiatan\r\n- Kebijakan telah dikomunikasikan kepada pimpinan (struktural) dan pegawai','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(140,28,'E','Terdapat kebijakan yang mengatur pemisahan fungsi dalam proses transaksi dan kejadian','Kebijakan telah mengatur:\r\n- Tanggung jawab dan tugas atas transaksi atau kejadian telah dipisahkan di antara pegawai berbeda yang terkait dengan otorisasi, persetujuan, pemrosesan dan pencatatan, pembayaran dan penerimaan dana, reviu dan audit, penyimpanan dan penanganan aset\r\n- Pelimpahan tugas dan kewenangan secara sistematik ke sejumlah orang untuk memastikan terdapat proses check and balances','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(141,29,'A','Proses otorisasi atas transaksi dan kejadian telah diperbaiki secara berkelanjutan dan secara optimal mampu mendukung pencapaian tujuan organisasi','- Fungsi otorisasi telah mampu menyesuaikan dengan perubahan lingkungan strategis\r\n- Fungsi otorisasi secara efektif mampu memitigasi risiko kolusi dan penyalahgunaan wewenang\r\n- Fungsi otorisasi mampu membuat pelaksanaan program dan kegiatan lebih efektif dalam mencapai tujuan organisasi','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(142,29,'B','Kebijakan dan implementasi terkait otorisasi atas transaksi dan kejadian telah dievaluasi sehingga dapat diketahui efektivitasnya','Kebijakan dan implementasi telah dievaluasi dengan ketentuan:\r\n- Berkala .\r\n- Terdokumentasi\r\n- Dilakukan untuk menangani residual risk\r\n- Hasil evaluasi telah ditindak lanjuti \r\n- Perbaikan telah menghasilkan kinerja yang lebih baik','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(143,29,'C','Otorisasi atas transaksi dan kejadian telah dilaksanakan sesuai kebijakan/prosedur yang ditetapkan','- Otorisasi dilaksanakan sesuai ketentuan (struktur organisasi, peraturan/keputusan, SOP, petunjuk teknis/petunjuk pelaksanaan, dan/atau kebijakan lain)\r\n- Fungsi otorisasi dilaksanakan baik pada kegiatan yang terkait dengan keuangan maupun kegiatan teknis operasional organisasi\r\n- Fungsi otorisasi dilakukan sebagai upaya untuk menangani risiko yang disebabkan kelemahan alur/prosedur','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(144,29,'D','Kebijakan terkait otorisasi atas transaksi dan kejadian telah dikomunikasikan dan dipahami oleh pihak yang berkepentingan','- Kebijakan telah dipahami oleh penanggungjawab pengelolaan keuangan/kegiatan\r\n- Kebijakan telah dikomunikasikan kepada pimpinan (struktural) dan pegawai','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(145,29,'E','Terdapat kebijakan yang mengatur prosedur otorisasi atas transaksi dan kejadian','Kebijakan telah mengatur:\r\n- Kondisi dan/atau syarat spesifik suatu transaksi atau kejadian dapat diotorisasi\r\n- Pihak yang berwenang melakukan otorisasi sesuai lingkup otoritasnya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(146,30,'A','Pencatatan atas transaksi dan kejadian telah diperbaiki secara berkelanjutan dan secara optimal mampu mendukung pencapaian tujuan organisasi','- Proses pencatatan telah mampu menyesuaikan dengan perubahan lingkungan strategis\r\n- Proses pencatatan secara efektif mampu memitigasi risiko manipulasi transaksi dan penyalahgunaan wewenang\r\n- Proses pencatatan mampu menghasilkan informasi yang relevan, bernilai, dan berguna bagi manajemen dalam mengendalikan operasi dan mengambil keputusan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(147,30,'B','Kebijakan dan implementasi terkait pencatatan atas transaksi dan kejadian telah dievaluasi sehingga dapat diketahui efektivitasnya','Kebijakan dan implementasi telah dievaluasi dengan ketentuan:\r\n- Berkala .\r\n- Terdokumentasi\r\n- Dilakukan untuk menangani residual risk\r\n- Hasil evaluasi telah ditindak lanjuti \r\n- Perbaikan telah menghasilkan kinerja yang lebih baik','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(148,30,'C','Pencatatan atas transaksi dan kejadian telah dilaksanakan sesuai kebijakan/prosedur yang ditetapkan','- Pencatatan dilaksanakan sesuai ketentuan (peraturan/keputusan, SOP, petunjuk teknis/petunjuk pelaksanaan, dan/atau kebijakan lain)\r\n- Pencatatan dilaksanakan baik pada kegiatan yang terkait dengan keuangan (akuntansi keuangan dan BMN/BMD) maupun kegiatan teknis operasional organisasi\r\n- Fungsi pencatatan dilakukan sebagai upaya untuk menangani risiko yang disebabkan kelemahan alur/prosedur','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(149,30,'D','Kebijakan terkait pencatatan atas transaksi dan kejadian telah dikomunikasikan dan dipahami oleh pihak yang berkepentingan','- Kebijakan telah dipahami oleh penanggungjawab pengelolaan keuangan/kegiatan\r\n- Kebijakan telah dikomunikasikan kepada pimpinan (struktural) dan pegawai','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(150,30,'E','Terdapat kebijakan yang mengatur prosedur pencatatan atas transaksi dan kejadian','Kebijakan telah mengatur:\r\n- Mekanisme pencatatan untuk seluruh siklus transaksi dan kejadian yang mencakup otorisasi, pelaksanaan, pemrosesan, dan klasifikasi akhir\r\n- Klasifikasi yang jelas untuk seluruh transaksi dan kejadian\r\n- Tenggat waktu pencatatan seluruh transaksi dan kejadian','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(151,31,'A','Pembatasan akses terhadap sumber daya dan pencatatannya telah diperbaiki secara berkelanjutan dan secara optimal mampu mendukung pencapaian tujuan organisasi','- Proses pembatasan akses telah mampu menyesuaikan dengan perubahan lingkungan strategis\r\n- Proses pembatasan akses secara efektif mampu memitigasi risiko penggunaan secara tidak sah dan penyalahgunaan wewenang\r\n- Menghasilkan zero significant fraudulent/dangerous intrusion','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(152,31,'B','Kebijakan dan implementasi terkait pembatasan akses terhadap sumber daya dan pencatatannya telah dievaluasi sehingga dapat diketahui efektivitasnya','Kebijakan dan implementasi telah dievaluasi dengan ketentuan:\r\n- Berkala\r\n- Terdokumentasi\r\n- Dilakukan untuk menangani residual risk\r\n- Hasil evaluasi telah ditindak lanjuti \r\n- Perbaikan telah menghasilkan kinerja yang lebih baik','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(153,31,'C','Terhadap sumber daya dan pencatatannya telah dilakukan pembatasan akses sesuai dengan ketentuan','- Pencatatan dilaksanakan sesuai ketentuan (peraturan/keputusan, SOP, petunjuk teknis/petunjuk pelaksanaan, dan/atau kebijakan lain)\r\n- Pembatasan akses dilaksanakan baik pada sumber daya yang dimiliki organisasi maupun terhadap pencatatan atas sumber daya tersebut\r\n- Pembatasan akses dilakukan dengan mempertimbangkan nilai aset, kemudahan dipindahkan, dan kemudahan ditukarkan\r\n- Pembatasan akses direviu secara periodik\r\n- Pembatasan akses dilakukan sebagai upaya untuk menangani risiko yang disebabkan kelemahan alur/prosedur','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(154,31,'D','Kebijakan terkait pembatasan akses terhadap sumber daya dan pencatatannya telah dikomunikasikan dan dipahami oleh pihak yang berkepentingan','- Kebijakan telah dipahami oleh penanggungjawab pengelolaan keuangan dan BMN/BMD\r\n- Kebijakan telah dikomunikasikan kepada pimpinan (struktural) dan pegawai','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(155,31,'E','Terdapat kebijakan yang mengatur prosedur pembatasan akses terhadap sumber daya yang dimiliki organisasi beserta pencatatannya','Kebijakan telah mengatur:\r\n- Mekanisme/desain pembatasan akses yang tidak diinginkan terhadap sumber daya\r\n- Mekanisme/desain pembatasan akses yang tidak diinginkan terhadap pencatatan sumber daya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(156,32,'A','Pertanggungjawaban terhadap sumber daya dan pencatatannya telah diperbaiki secara berkelanjutan dan secara optimal mampu mendukung pencapaian tujuan organisasi','- Proses pertanggungjawaban telah mampu menyesuaikan dengan perubahan lingkungan strategis\r\n- Proses pertanggungjawaban secara efektif mampu memitigasi risiko penggunaan secara tidak sah dan penyalahgunaan wewenang\r\n- Pertanggungjawaban terhadap sumber daya dan pencatatannya telah dibagi habis kepada pihak/pegawai sesuai dengan kewenangannya','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(157,32,'B','Kebijakan dan implementasi terkait akuntabilitas sumber daya dan pencatatannya telah dievaluasi sehingga dapat diketahui efektivitasnya','Kebijakan dan implementasi telah dievaluasi dengan ketentuan:\r\n- Berkala .\r\n- Terdokumentasi\r\n- Dilakukan untuk menangani residual risk\r\n- Hasil evaluasi telah ditindak lanjuti \r\n- Perbaikan telah menghasilkan kinerja yang lebih baik','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(158,32,'C','Sumber daya dan pencatatannya telah dipertanggungjawabkan oleh pihak/pegawai yang ditetapkan sesuai kebijakan/prosedur yang ditetapkan','- Pertanggungjawaban dilaksanakan sesuai ketentuan (peraturan/keputusan, SOP, petunjuk teknis/petunjuk pelaksanaan, dan/atau kebijakan lain)\r\n- Dilakukan perbandingan berkala antara sumber daya dengan pencatatannya\r\n- Pertanggungjawaban dilaksanakan baik pada kegiatan yang terkait dengan keuangan (akuntansi keuangan dan BMN/BMD) maupun kegiatan teknis operasional organisasi\r\n- Pertanggungjawaban terhadap sumber daya dan pencatatannya direviu secara periodik\r\n- Fungsi pertanggungjawaban dilakukan sebagai upaya untuk menangani risiko yang disebabkan kelemahan alur/prosedur','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(159,32,'D','Kebijakan terkait pertanggungjawaban sumber daya dan pencatatannya telah dikomunikasikan dan dipahami oleh pihak yang berkepentingan','- Kebijakan telah dipahami oleh penanggungjawab pengelolaan keuangan dan BMN/BMD\r\n- Kebijakan telah dikomunikasikan kepada pimpinan (struktural) dan pegawai','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(160,32,'E','Terdapat kebijakan yang mengatur prosedur pertanggungjawaban sumber daya dan pencatatannya','Kebijakan telah mengatur:\r\n- Mekanisme pertanggungjawaban penyimpanan, penggunaan, dan pencatatan sumber daya\r\n- Penetapan pihak/pegawai yang harus bertanggungjawab\r\n- Penetapan bentuk pertanggungjawaban yang harus dilaksanakan/dibuat','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(161,33,'A','Pendokumentasian atas SPI serta transaksi dan kejadian penting telah diperbaiki secara berkelanjutan dan secara optimal mampu mendukung pencapaian tujuan organisasi','- Proses pendokumentasian telah mampu menyesuaikan dengan perubahan lingkungan strategis\r\n- Proses pendokumentasian mampu menghasilkan dokumen yang relevan, bernilai, dan berguna bagi manajemen dan pihak lain secara real time','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(162,33,'B','Pendokumentasian atas SPI serta transaksi dan kejadian penting telah dievaluasi sehingga dapat diketahui efektivitasnya','Kebijakan dan implementasi telah dievaluasi dengan ketentuan:\r\n- Berkala .\r\n- Terdokumentasi\r\n- Dilakukan untuk menangani residual risk\r\n- Hasil evaluasi telah ditindak lanjuti \r\n- Perbaikan telah menghasilkan kinerja yang lebih baik','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(163,33,'C','Pendokumentasian atas SPI serta transaksi dan kejadian penting telah dilaksanakan sesuai kebijakan/prosedur yang ditetapkan','- Pendokumentasian dilaksanakan sesuai ketentuan (peraturan/keputusan, SOP, petunjuk teknis/petunjuk pelaksanaan, dan/atau kebijakan lain)\r\n- Dokumentasi dan catatan dikelola, dipelihara, dan dimutakhirkan secara berkala\r\n- Pendokumentasian dilaksanakan secara manual dan/atau elektronik sesuai karakteristik dokumen dan kebutuhan organisasi\r\n- Pendokumentasian dilaksanakan baik pada kegiatan yang terkait dengan keuangan (akuntansi keuangan dan BMN/BMD) maupun kegiatan teknis operasional organisasi\r\n- Fungsi pendokumentasian dilakukan sebagai upaya untuk menangani risiko yang disebabkan kelemahan alur/prosedur','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(164,33,'D','Kebijakan terkait prosedur pendokumentasian atas SPI serta transaksi dan kejadian penting telah dikomunikasikan dan dipahami oleh pihak yang berkepentingan','- Kebijakan telah dipahami oleh penanggungjawab pengelolaan dokumen/arsip\r\n- Kebijakan telah dikomunikasikan kepada pimpinan (struktural), pegawai, dan stakeholders','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(165,33,'E','Terdapat kebijakan yang mengatur prosedur pendokumentasian atas SPI serta transaksi dan kejadian penting','Kebijakan telah mengatur:\r\n- Pendokumentasian secara manual dan elektronik\r\n- Mencakup seluruh pendokumentasian  pengendalian serta transaksi dan kejadian penting\r\n- Untuk pendokumentasian secara elektronik mencakup sistem informasi otomatis, pengumpulan dan penanganan data, serta pengendalian umum dan pengendalian aplikasi','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(166,34,'A','Informasi yang disajikan relevan dan memenuhi ekspektasi stakeholder','- Informasi produk, standar, prosedur layanan/pelaksanaan tugas fungsi dan pengaduan telah memenuhi ekspektasi stakeholder;\r\n- Informasi layanan internal (keuangan, kepegawaian, umum, dsb) telah memenuhi ekspektasi stakeholder;\r\n- Informasi manajemen kinerja (rencana kinerja, capaian kinerja, dsb) telah memenuhi ekspektasi stakeholder.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(167,34,'B','Klasifikasi informasi telah dievaluasi dan ditindaklanjuti sehingga dapat disajikan dengan tepat waktu, andal, dan relevan','- Informasi produk, standar, prosedur layanan/pelaksanaan tugas fungsi dan pengaduan telah dievaluasi dan ditindaklanjuti sehingga:\r\na. Jelas klasifikasi informasi;\r\nb. Jelas prosedur pengelolaan informasi;\r\nc. Disajikan tepat waktu, andal, dan relevan.\r\n\r\n- Informasi layanan internal (keuangan, kepegawaian, umum, dsb) telah dievaluasi dan ditindaklanjuti sehingga:\r\na. Jelas klasifikasi informasi;\r\nb. Jelas prosedur pengelolaan informasi;\r\nc. Disajikan tepat waktu, andal, dan relevan.\r\n\r\n- Informasi manajemen kinerja (rencana kinerja, capaian kinerja, dsb) telah dievaluasi dan ditindaklanjuti sehingga:\r\na. Jelas klasifikasi informasi;\r\nb. Jelas prosedur pengelolaan informasi;\r\nc. Disajikan tepat waktu, andal, dan relevan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(168,34,'C','Informasi yang relevan untuk mendukung pengendalian intern tersedia secara lengkap dan mudah untuk diperoleh','- Informasi produk, standar, prosedur layanan/pelaksanaan tugas fungsi dan pengaduan tersedia secara lengkap dan mudah diakses;\r\n- Informasi layanan internal (keuangan, kepegawaian, umum, dsb) tersedia secara lengkap dan mudah diakses;\r\n- Informasi manajemen kinerja (rencana kinerja, capaian kinerja, dsb) tersedia  secara lengkap dan mudah diakses.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(169,34,'D','Informasi yang relevan untuk mendukung pengendalian intern tersedia secara lengkap namun tidak mudah diperoleh/akses terbatas','- Informasi produk, standar, prosedur layanan/pelaksanaan tugas fungsi dan pengaduan tersedia secara lengkap, namun tidak mudah diakses;\r\n- Informasi layanan internal (keuangan, kepegawaian, umum, dsb) tersedia secara lengkap, namun tidak mudah diakses.\r\n- Informasi manajemen kinerja (rencana kinerja, capaian kinerja, dsb) tersedia secara lengkap, namun tidak mudah diakses','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(170,34,'E','Ketersediaan informasi yang relevan untuk mendukung pengendalian intern tidak lengkap','- Informasi produk, standar, prosedur layanan/pelaksanaan tugas fungsi dan pengaduan belum tersedia secara lengkap;\r\n- Informasi layanan internal (keuangan, kepegawaian, umum, dsb) belum tersedia secara lengkap;\r\n- Informasi manajemen kinerja (rencana kinerja, capaian kinerja, dsb) belum tersedia secara lengkap;','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(171,35,'A','Sistem pengaduan berdampak pada perbaikan berkelanjutan','Perbaikan berkelanjutan antara lain berdampak pada peningkatan kinerja, perbaikan pelayanan publik, dan kepuasan stakeholder.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(172,35,'B','Sistem pengaduan telah dievaluasi','Kebijakan dan implementasi telah dievaluasi dengan ketentuan:\r\n- Berkala\r\n- Terdokumentasi\r\n- Dilakukan untuk menangani residual risk\r\n- Hasil evaluasi telah ditindak lanjuti \r\n- Perbaikan telah menghasilkan kinerja yang lebih baik','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(173,35,'C','Sistem pengaduan telah diterapkan dan ditindaklanjuti sesuai Kebijakan/SOP','Sudah Jelas','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(174,35,'D','Keberadaan sistem pengaduan telah disosialisasikan kepada masyarakat/stakeholder','Sudah Jelas','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(175,35,'E','Telah terdapat kebijakan penerapan sistem pengaduan','Sudah Jelas','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(176,36,'A','Strategi dan kebijakan manajemen risiko telah dikomunikasikan pada seluruh pegawai pada tingkat operasional unit kerja, tingkat strategis unit kerja, dan tingkat strategis K/L/D','>60%  pegawai sample pada tingkat operasional unit kerja, strategis unit kerja, dan strategis K/L/D menunjukan pengetahuan akan strategi dan kebijakan yang telah ditetapkan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(177,36,'B','Strategi dan kebijakan manajemen risiko telah dikomunikasikan pada seluruh pegawai pada tingkat operasional unit kerja dan tingkat strategis unit kerja','>60%  pegawai sample pada tingkat operasional unit kerja dan strategis unit kerja menunjukan pengetahuan akan strategi dan kebijakan yang telah ditetapkan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(178,36,'C','Strategi dan kebijakan manajemen risiko telah dikomunikasikan pada seluruh pegawai pada tingkat operasional unit kerja dan sebagian pegawai pada tingkat strategis unit kerja','>60%  pegawai sample pada tingkat operasional unit kerja dan <60% pada tingkat strategis unit kerja  menunjukan pengetahuan akan strategi dan kebijakan yang telah ditetapkan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(179,36,'D','Strategi dan kebijakan manajemen risiko telah dikomunikasikan pada seluruh pegawai pada tingkat operasional unit kerja','>60%  pegawai sample pada tingkat operasional unit kerja menunjukan pengetahuan akan strategi dan kebijakan yang telah ditetapkan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(180,36,'E','Strategi dan kebijakan manajemen risiko telah dikomunikasikan pada sebagian pegawai pada tingkat operasional unit kerja','<60%  pegawai sample pada tingkat operasional unit kerja menunjukan pengetahuan akan strategi dan kebijakan yang telah ditetapkan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(181,37,'A','Register risiko dan rencana tindak pengendalian tingkat operasional Unit Kerja/OPD, strategis Unit Kerja/OPD dan Strategis K/L/D telah dikomunikasikan kepada seluruh pihak terkait dan dijadikan bahan dalam pengambilan keputusan  serta menjadi bahan pembelajaran dan inovasi','Komunikasi Register risiko dan rencana tindak pengendalian tingkat operasional Unit Kerja/OPD, dan strategis Unit Kerja/OPD telah dilakukan kepada semua pihak yang telah diidentifikasi dalam rencana komunikasi sebagaimana tertuang dalam dokumen RTP yang telah disusun sebelumnya dan dijadikan bahan pembuatan keputusan oleh pihak-pihak tersebut serta menjadi bahan pembelajaran dan inovasi bagi K/L/D','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(182,37,'B','Register risiko dan rencana tindak pengendalian tingkat operasional Unit Kerja/OPD, strategis Unit Kerja/OPD dan Strategis K/L/D telah dikomunikasikan kepada seluruh pihak terkait dan dijadikan bahan dalam pengambilan keputusan','Komunikasi Register risiko dan rencana tindak pengendalian tingkat operasional Unit Kerja/OPD, dan strategis Unit Kerja/OPD telah dilakukan kepada semua pihak yang telah diidentifikasi dalam rencana komunikasi sebagaimana tertuang dalam dokumen RTP yang telah disusun sebelumnya dan dijadikan bahan pembuatan keputusan oleh pihak-pihak tersebut.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(183,37,'C','Register risiko dan rencana tindak pengendalian operasional Unit Kerja/OPD, strategis Unit Kerja/OPD dan Strategis K/L/D telah dikomunikasikan kepada seluruh pihak terkait','Komunikasi Register risiko dan rencana tindak pengendalian tingkat operasional Unit Kerja/OPD, strategis Unit Kerja/OPD dan strategis K/L/D telah dilakukan kepada semua pihak yang telah diidentifikasi dalam rencana komunikasi sebagaimana tertuang dalam dokumen RTP yang telah disusun sebelumnya.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(184,37,'D','Register risiko dan rencana tindak pengendalian tingkat operasional unit kerja/OPD dan strategis unit kerja/OPD telah dikomunikasikan kepada seluruh pihak terkait','Komunikasi Register risiko dan rencana tindak pengendalian tingkat operasional Unit Kerja/OPD dan strategis Unit Kerja/OPD telah dilakukan kepada semua pihak yang telah diidentifikasi dalam rencana komunikasi sebagaimana tertuang dalam dokumen RTP yang telah disusun sebelumnya.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(185,37,'E','Register risiko dan rencana tindak pengendalian tingkat operasional unit kerja telah dikomunikasikan kepada sebagian pihak terkait','Komunikasi Register risiko dan rencana tindak pengendalian tingkat operasional Unit Kerja/OPD tidak dilakukan kepada semua pihak yang telah diidentifikasi dalam rencana komunikasi sebagaimana tertuang dalam dokumen RTP yang telah disusun sebelumnya.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(186,38,'A','Perbaikan berkelanjutan atas metodologi komunikasi yang efektif','Perbaikan berkelanjutan atas komunikasi yang efektif menghasilkan:\r\n- Upaya promosi/sosialisasi tentang produk/layanan/ pelaksanaan tugas fungsi yang telah berhasil meningkatkan kepercayaan publik/stakholder;\r\n- Upaya komunikasi dengan publik/stakeholder yang  telah berhasil memperbaiki citra instansi.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(187,38,'B','Komunikasi yang efektif telah dilakukan kepada internal dan eksternal secara terstruktur dan berkala dan telah dievaluasi','- Telah dilakukan evaluasi terhadap upaya promosi/sosialisasi tentang produk/layanan/ pelaksanaan tugas fungsi yang menghasilkan perbaikan.\r\nContohnya: melalui evaluasi kepuasan layanan, survei citra instansi di mata stakeholder\r\n- Telah dilakukan evaluasi terhadap upaya komunikasi dengan publik/stakeholder untuk mengatasi isu negatif, yang menghasilkan perbaikan','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(188,38,'C','Komunikasi yang efektif telah dilakukan kepada internal dan eksternal secara terstruktur dan berkala','- Upaya promosi/sosialisasi tentang produk/layanan/ pelaksanaan tugas fungsi dalam rangka meningkatkan kepercayaan publik/stakholder telah dilakukan secara terstruktur dan berkala;\r\n- Upaya komunikasi dengan publik/stakeholder untuk mengatasi isu negatif telah dilakukan secara terstruktur dan berkala;\r\n- Seluruh pegawai telah memahami visi, misi, tujuan, sasaran strategis, fokus dan prioritas secara terstruktur dan berkala;\r\n- Seluruh pegawai telah memahami risiko dan kegiatan pengendalian.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(189,38,'D','Komunikasi yang efektif telah dilakukan kepada internal dan eksternal namun belum terstruktur dan berkala','- Upaya promosi/sosialisasi tentang produk/layanan/ pelaksanaan tugas fungsi dalam rangka meningkatkan kepercayaan publik/stakholder telah dilakukan;\r\n- Upaya komunikasi dengan publik/stakeholder untuk mengatasi isu negatif telah dilakukan;\r\n- Telah dilakukan pengkomunikasian pengarahan tentang visi, misi, tujuan, sasaran strategis, fokus dan prioritas namun belum dilakukan secara terstruktur dan berkala;\r\n- Telah dilakukan komunikasi terkait risiko dan kegiatan pengendalian namun belum dilakukan secara terstruktur dan berkala.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(190,38,'E','Komunikasi yang efektif dengan eksternal belum dilakukan','- Upaya promosi/sosialisasi tentang produk/layanan/ pelaksanaan tugas fungsi dalam rangka meningkatkan kepercayaan publik/stakholder belum dilakukan;\r\n- Upaya komunikasi dengan publik/stakeholder untuk mengatasi isu negatif belum dilakukan;\r\n- Telah dilakukan pengkomunikasian pengarahan tentang visi, misi, tujuan, sasaran strategis, fokus dan prioritas namun belum terstruktur dan berkala;\r\n- Telah dilakukan komunikasi terkait risiko dan kegiatan pengendalian namun belum terstruktur dan berkala.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(191,39,'A','Perbaikan berkelanjutan atas pemantauan pengendalian intern dilaksanakan dan berdampak pada kualitas pengendalian intern','a. Pemantauan atas pelaksanaan pengendalian telah efektif mengurangi dampak dan frekuensi keterjadian risiko;\r\nb. Terdapat sistem informasi terintegrasi untuk memantau pengendalian untuk seluruh proses bisnis secara realtime.\r\nc. Pemantauan kinerja digunakan sebagai dasar dalam reward and punishment;\r\nd. Didukung oleh sistem informasi pemantauan kinerja yang terintegrasi.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(192,39,'B','Seluruh hasil pemantauan berkelanjutan dikelola dan ditindaklanjuti','Seluruh hasil pemantauan dikelola dan ditindaklanjuti.\r\nPemantauan dilaksanakan:\r\na. Secara berkala; \r\nb.  Pemantauan menilai pelaksanaan pengendalian (membandingkan rencana tindak pengendalian dengan pelaksanaan dan memberikan rekomendasi perbaikan);\r\nc. Hasil pemantauan dikomunikasikan kepada seluruh anggota organisasi.\r\n\r\nPemantauan atas kinerja K/L/D, unit level I, unit level II, unit level III dan pemantauan kinerja individu membahas:        \r\na. Capaian pelaksanaan rincana aksi;\r\nb. Hambatan;\r\nc. Rencana ke depan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(193,39,'C','Pemantauan pelaksanaan pengendalian telah dilaksanakan pada seluruh aktivitas pengendalian dan terkait pemantauan kinerja telah dilaksanakan pada level program, kegiatan, unit kerja level dibawahnya sampai dengan pemantauan kinerja individu, namun hasil pemantauan belum dikelola (tidak lanjut tidak termonitor)','Pemantauan dilakukan pada seluruh aktivitas pengendalian.\r\nPemantauan dilaksanakan:\r\na. Secara berkala; \r\nb.  Pemantauan menilai pelaksanaan pengendalian (membandingkan rencana tindak pengendalian dengan pelaksanaan dan memberikan rekomendasi perbaikan);\r\nc. Hasil pemantauan dikomunikasikan kepada seluruh anggota organisasi.\r\n\r\nPemantauan atas kinerja K/L/D, unit level I, unit level II, unit level III dan pemantauan kinerja individu membahas:        \r\na. Capaian pelaksanaan rincana aksi;\r\nb. Hambatan;\r\nc. Rencana ke depan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(194,39,'D','Pemantauan pelaksanaan pengendalian telah dilaksanakan pada sebagian aktivitas pengendalian dan terkait pemantauan kinerja telah dilaksanakan pada level program dan kegiatan','Pemantauan dilakukan pada sebagian aktivitas pengendalian.\r\nPemantauan dilaksanakan:\r\na. Secara berkala; \r\nb.  Pemantauan menilai pelaksanaan pengendalian (membandingkan rencana tindak pengendalian dengan pelaksanaan dan memberikan rekomendasi perbaikan);\r\nc. Hasil pemantauan dikomunikasikan kepada seluruh anggota organisasi.\r\n\r\nPemantauan atas kinerja K/L/D, unit level I, unit level II, unit level III dan pemantauan kinerja individu membahas:        \r\na. Capaian pelaksanaan rincana aksi;\r\nb. Hambatan;\r\nc. Rencana ke depan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(195,39,'E','Pemantauan pelaksanaan pengendalian telah dilaksanakan','- Pemantauan pelaksanaan pengendalian telah dilaksanakan;\r\n- Pemantauan pelaksanaan kinerja telah dilaksanakan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(196,40,'A','Sudah dilakukan reviu atas seluruh risiko operasional unit kerja, strategis unit kerja, dan strategis K/L/D dan hasil reviu dijadikan bahan perbaikan organisasi','Kebijakan, framework, metode, tahapan, proses, dan praktik yang dijalankan terkait dengan proses manajemen risiko telah direviu oleh pihak internal dari Instansi Pemerintah (oleh APIP maupun komite manajemen risiko) untuk semua risiko operasional unit kerja, strategis unit kerja, strategis K/L/D.  Hasil reviu telah seluruhnya ditindaklanjuti dan sudah ada implementasi perbaikan atas hasil reviu tersebut.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(197,40,'B','Sudah dilakukan reviu atas seluruh risiko operasional unit kerja, strategis unit kerja, dan strategis K/L/D','Kebijakan, framework, metode, tahapan, proses, dan praktik yang dijalankan terkait dengan proses manajemen risiko telah direviu oleh pihak internal dari Instansi Pemerintah (oleh APIP maupun komite manajemen risiko) untuk semua risiko operasional unit kerja, strategis unit kerja, strategis K/L/D','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(198,40,'C','Sudah dilakukan reviu atas seluruh risiko operasional unit kerja dan strategis unit kerja','Kebijakan, framework, metode, tahapan, proses, dan praktik yang dijalankan terkait dengan proses manajemen risiko telah direviu oleh pihak internal dari Instansi Pemerintah (oleh APIP maupun komite manajemen risiko) tetapi hanya atas risiko operasional unit kerja dan strategis unit kerja','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(199,40,'D','Sudah dilakukan reviu atas seluruh risiko operasional unit kerja','Kebijakan, framework, metode, tahapan, proses, dan praktik yang dijalankan terkait dengan proses manajemen risiko telah direviu oleh pihak internal dari Instansi Pemerintah (oleh APIP maupun komite manajemen risiko) tetapi hanya atas risiko operasional unit kerja','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(200,40,'E','Sudah dilakukan reviu atas sebagian risiko operasional unit kerja','Kebijakan, framework, metode, tahapan, proses, dan praktik yang dijalankan terkait dengan proses manajemen risiko belum direviu oleh pihak internal dari Instansi Pemerintah (oleh APIP maupun komite manajemen risiko) dan hanya atas sebagian risiko operasional unit kerja','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(201,41,'A','Monitoring terhadap risiko dan tindak pengendalian dilakukan terhadap risiko operasional unit kerja, strategis unit kerja, dan strategis K/L/D secara memadai dan menjadi bahan pembelajaran bagi unit kerja','Memadai berarti:\r\n1.Telah ada langkah Monitoring sesuai kebijakan;\r\n2. Monitoring dilakukan sesuai dengan jadwal yang ditetapkan sesuai kebijakan;\r\n3. Monitoring dilakukan oleh unit kepatuhan dan dilaksanakan minimal satu kali per semester atau sesuai dengan kebutuhan;\r\n4. Proses dan hasil Monitoring telah didokumentasikan;\r\n5. Monitoring sepenuhnya dilakukan terhadap:\r\na. implementasi pengendalian;\r\nb. kejadian risiko  (termasuk mekanisme dan implementasi pelaporan segera);\r\nc. Memantau pelaksanaan tiap tahapan pengelolaan risiko.\r\n6. Hasil monitoring menunjukkan kondisi yang baik;\r\n7. Hasil Monitoring seluruhnya telah ditindaklanjuti.\r\n9. Terdapat implementasi perbaikan atas hasil monitoring','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(202,41,'B','Monitoring terhadap risiko dan tindak pengendalian dilakukan terhadap risiko operasional unit kerja/OPD, strategis unit kerja/OPD dan strategis K/L/D secara memadai','Memadai berarti:\r\n1.Telah ada langkah Monitoring sesuai kebijakan;\r\n2. Monitoring dilakukan sesuai dengan jadwal yang ditetapkan sesuai kebijakan;\r\n3. Monitoring dilakukan oleh unit kepatuhan dan dilaksanakan minimal satu kali per semester atau sesuai dengan kebutuhan;\r\n4. Proses dan hasil Monitoring telah didokumentasikan;\r\n5. Monitoring sepenuhnya dilakukan terhadap:\r\na. implementasi pengendalian;\r\nb. kejadian risiko  (termasuk mekanisme dan implementasi pelaporan segera);\r\nc. Memantau pelaksanaan tiap tahapan pengelolaan risiko.\r\n6. Hasil monitoring menunjukkan kondisi yang baik;\r\n7. Hasil Monitoring sebagian telah diditindaklanjuti.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(203,41,'C','Monitoring terhadap risiko dan tindak pengendalian dilakukan terhadap risiko operasional unit kerja/OPD dan strategis unit kerja/OPD secara memadai','Memadai berarti:\r\n1.Telah ada langkah Monitoring sesuai kebijakan;\r\n2. Monitoring dilakukan sesuai dengan jadwal yang ditetapkan sesuai kebijakan;\r\n3. Monitoring dilakukan oleh unit kepatuhan dan dilaksanakan minimal satu kali per semester atau sesuai dengan kebutuhan;\r\n4. Proses dan hasil Monitoring telah didokumentasikan;\r\n5. Monitoring sepenuhnya dilakukan terhadap:\r\na. implementasi pengendalian;\r\nb. kejadian risiko  (termasuk mekanisme dan implementasi pelaporan segera);\r\nc. Memantau pelaksanaan tiap tahapan pengelolaan risiko.\r\n6. Hasil monitoring menunjukkan kondisi yang baik;\r\n7. Hasil Monitoring sebagian telah diditindaklanjuti.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(204,41,'D','Monitoring terhadap risiko dan tindak pengendalian dilakukan terhadap risiko operasional unit kerja/OPD secara memadai','Memadai berarti:\r\n1.Telah ada langkah Monitoring sesuai kebijakan;\r\n2. Monitoring dilakukan sesuai dengan jadwal yang ditetapkan sesuai kebijakan;\r\n3. Monitoring dilakukan oleh unit kepatuhan dan dilaksanakan minimal satu kali per semester atau sesuai dengan kebutuhan;\r\n4. Proses dan hasil Monitoring telah didokumentasikan;\r\n5. Monitoring sepenuhnya dilakukan terhadap:\r\na. implementasi pengendalian;\r\nb. kejadian risiko  (termasuk mekanisme dan implementasi pelaporan segera);\r\nc. Memantau pelaksanaan tiap tahapan pengelolaan risiko.\r\n6. Hasil monitoring menunjukkan kondisi yang baik;\r\n7. Hasil Monitoring sebagian telah diditindaklanjuti.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(205,41,'E','Monitoring terhadap risiko dan tindak pengendalian dilakukan terhadap risiko operasional unit kerja/OPD namun belum memadai','Belum memadai berarti:\r\n1. Monitoring dilakukan tidak sesuai jadwal yang ditetapkan;\r\n2. Monitoring dilakukan oleh atasan langsung unit UPR dan dilaksanakan minimal satu kali dalam satu tahun;\r\n3. Proses dan hasil Monitoring tidak didokumentasikan;\r\n4. Monitoring belum sepenuhnya dilakukan terhadap:\r\na. implementasi pengendalian;\r\nb. kejadian risiko (termasuk mekanisme dan implementasi pelaporan segera);\r\nc. Memantau pelaksanaan tiap tahapan pengelolaan risiko.\r\n5. Hasil monitoring menunjukkan kondisi yang belum baik;\r\n6. Hasil Monitoring tidak ditindaklanjuti.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(206,42,'A','Perbaikan berkelanjutan atas pelaksanaan evaluasi terpisah berdampak pada peningkatan kualitas pengendalian intern dan pencapaian tujuan organisasi','- Hasil tindak lanjut mampu mengurangi dampak dan frekuensi risiko.\r\n- Hasil tindak lanjut mampu mengakselerasi pencapaian indikator program dan kegiatan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(207,42,'B','Seluruh hasil evaluasi terpisah dikelola dan ditindaklanjuti','Seluruh hasil evaluasi terpisah dikelola dan ditindaklanjuti. Pengelolaan hasil antara lain dilakukan dengan dokumentasi yang baik dan monitoring atas penyelesaian tindak lanjut hasil evaluasi terpisah.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(208,42,'C','Evaluasi terpisah telah dilaksanakan pada seluruh aktivitas pengendalian dan seluruh program dan kegiatan serta dilaksanakan oleh pihak yang kompeten dan dengan metodologi yang tepat, namun hasil evaluasi terpisah belum ditindaklanjuti seluruhnya','- Evaluasi dilakukan pada seluruh aktivitas pengendalian.\r\nEvaluasi dianggap dilaksanakan jika:\r\na. Dilaksanakan oleh pihak yang kompeten dan independen;\r\nb. Evaluasi menilai kecukupan pelaksanaan pengendalian (maturitas dan efektifitas pengendalian);\r\nc. Memberikan rekomendasi yang relevan;\r\nd. Rekomendasi perbaikan telah ditindaklanjuti sebagian.\r\n\r\n- Evaluasi dilakukan pada seluruh program kegiatan.\r\nEvaluasi dianggap dilaksanakan jika:\r\na. Dilaksanakan oleh pihak yang kompeten dan independen;\r\nb. Evaluasi menilai keselarasan prgram dan program dengan sasaran;\r\nc. Memberikan rekomendasi yang relevan;\r\nd. Rekomendasi perbaikan telah ditindaklanjuti sebagian.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(209,42,'D','Evaluasi terpisah telah dilaksanakan pada sebagian aktivitas pengendalian dan seluruh program dan kegiatan serta dilaksanakan oleh pihak yang kompeten dengan metodologi yang tepat','- Evaluasi dilakukan pada sebagian aktivitas pengendalian.\r\nEvaluasi dianggap dilaksanakan jika:\r\na. Dilaksanakan oleh pihak yang kompeten dan independen;\r\nb. Evaluasi menilai kecukupan pelaksanaan pengendalian (maturitas dan efektifitas pengendalian);\r\nc. Memberikan rekomendasi yang relevan.\r\n\r\n- Evaluasi dilakukan pada sebagian program kegiatan.\r\na. Dilaksanakan oleh pihak yang kompeten dan independen;\r\nb. Evaluasi menilai keselarasan prgram dan program dengan sasaran;\r\nc. Memberikan rekomendasi yang relevan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(210,42,'E','Evaluasi terpisah atas pengendalian intern dan pelaksanaan program/kegiatan telah dilaksanakan','- Evaluasi atas pelaksanaan pengendalian intern telah dilaksanakan; \r\n- Evaluasi atas pelaksanaan program/kegiatan telah dilaksanakan.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(211,43,'A','Reviu terhadap proses tindak pengendalian risiko tingkat operasional unit kerja/OPD, strategis unit kerja/OPD, dan strategis K/L/D sangat memadai','Sangat memadai berarti:\r\n1.Telah ada pedoman reviu yang terstandar yang merunjuk pada best practice;\r\n2. Reviu dilakukan sesuai dengan jadwal yang ditetapkan dan sesuai dengan pedoman;\r\n3. Reviu dilakukan oleh APIP minimal satu kali per tahun;\r\n4. Proses dan hasil reviu telah didokumentasikan serta dapat disimpulkan baik;\r\n5. Reviu dilakukan untuk mereviu rencana dan implementasi pengendalian serta kejadian risiko serta respon yang dilakukan\r\n6. Hasil reviu menunjukkan kondisi yang seluruhnya telah sesuai dengan standar dan kebijakan serta dapat disimpulkan baik;\r\n7. Hasil reviu seluruhnya telah diditindaklanjut;\r\n9. Terdapat implementasi perbaikan atas hasil reviu.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(212,43,'B','Reviu terhadap proses tindak pengendalian untuk risiko tingkat operasional unit kerja/OPD, strategis unit kerja/OPD, dan strategis K/L/D memadai','Memadai berarti:\r\n1.Telah ada pedoman reviu yang terstandar yang merujuk pada best practice;\r\n2. Reviu dilakukan sesuai dengan jadwal yang ditetapkan dan sesuai dengan pedoman;\r\n3. Reviu dilakukan oleh APIP minimal satu kali per tahun;\r\n4. Proses dan hasil reviu telah didokumentasikan;\r\n5. Reviu dilakukan untuk mereviu rencana dan implementasi pengendalian serta kejadian risiko serta respon yang dilakukan\r\n6. Hasil reviu menunjukkan sebagian besar kondisi yang ada telah sesuai dengan standar dan kebijakan serta dapat disimpulkan baik;\r\n7. Hasil reviu sebagian besar telah diditindaklanjuti.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(213,43,'C','Reviu terhadap proses tindak pengendalian untuk risiko tingkat operasional unit kerja/OPD dan strategis unit kerja/OPD memadai','Memadai berarti:\r\n1.Telah ada pedoman reviu yang terstandar;\r\n2. Reviu dilakukan sesuai dengan jadwal yang ditetapkan dan pedoman yang terstandar;\r\n3. Reviu dilakukan oleh APIP dan dilaksanakan minimal satu kali per tahun;\r\n4. Proses dan hasil reviu telah didokumentasikan;\r\n5. Reviu dilakukan untuk mereviu rencana dan implementasi pengendalian serta kejadian risiko serta respon yang dilakukan\r\n6. Hasil reviu menunjukkan sebagian besar kondisi yang ada telah sesuai dengan standar dan kebijakan serta dapat disimpulkan baik;\r\n7. Hasil reviu sebagian besar telah diditindaklanjuti.','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(214,43,'D','Reviu terhadap proses tindak pengendalian untuk risiko tingkat operasional unit kerja/OPD cukup memadai','Cukup memadai berarti:\r\n1. Reviu dilakukan tidak sesuai jadwal yang ditetapkan;\r\n2. Belum ada pedoman reviu yang terstandar\r\n3. Reviu dilakukan oleh APIP dan dilaksanakan minimal satu kali per tahun;\r\n4. Proses dan hasil reviu telah didokumentasikan;\r\n5. Reviu dilakukan untuk mereviu rencana dan implementasi pengendalian serta kejadian risiko serta respon yang dilakukan\r\n6. Hasil reviu menunjukkan sebagian kondisi yang ada sesuai dengan standar dan kebijakan;\r\n7. Hasil reviu sebagian kecil ditindaklanjuti;','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(215,43,'E','Reviu terhadap proses tindak pengendalian untuk risiko tingkat operasional unit kerja/OPD belum memadai','Belum memadai berarti:\r\n1. Reviu dilakukan tidak sesuai jadwal yang ditetapkan;\r\n2. Belum ada pedoman reviu yang terstandar\r\n3. Reviu dilakukan oleh APIP dan dilaksanakan minimal satu kali per tahun;\r\n4. Proses dan hasil reviu telah didokumentasikan;\r\n5. Reviu dilakukan untuk mereviu rencana dan implementasi pengendalian serta kejadian risiko serta respon yang dilakukan\r\n6. Hasil reviu menunjukkan sebagian kecil kondisi yang ada sesuai dengan standar dan kebijakan;\r\n7. Hasil reviu belum ditindaklanjuti;','W/D/O','2026-06-24 02:30:31','2026-06-24 02:30:31'),(216,44,'E','Kriteria Level 1 untuk Kebijakan Antikorupsi: Kebijakan pencegahan korupsi telah ditetapkan dan dikomunikasikan.','Panduan pengujian tingkat 1',NULL,'2026-06-24 02:30:31','2026-06-24 02:30:31'),(217,44,'D','Kriteria Level 2 untuk Kebijakan Antikorupsi: Kebijakan pencegahan korupsi telah ditetapkan dan dikomunikasikan.','Panduan pengujian tingkat 2',NULL,'2026-06-24 02:30:31','2026-06-24 02:30:31'),(218,44,'C','Kriteria Level 3 untuk Kebijakan Antikorupsi: Kebijakan pencegahan korupsi telah ditetapkan dan dikomunikasikan.','Panduan pengujian tingkat 3',NULL,'2026-06-24 02:30:31','2026-06-24 02:30:31'),(219,44,'B','Kriteria Level 4 untuk Kebijakan Antikorupsi: Kebijakan pencegahan korupsi telah ditetapkan dan dikomunikasikan.','Panduan pengujian tingkat 4',NULL,'2026-06-24 02:30:31','2026-06-24 02:30:31'),(220,44,'A','Kriteria Level 5 untuk Kebijakan Antikorupsi: Kebijakan pencegahan korupsi telah ditetapkan dan dikomunikasikan.','Panduan pengujian tingkat 5',NULL,'2026-06-24 02:30:31','2026-06-24 02:30:31'),(221,45,'E','Kriteria Level 1 untuk Seperangkat Regulasi: Terdapat regulasi pendukung kebijakan pencegahan korupsi.','Panduan pengujian tingkat 1',NULL,'2026-06-24 02:30:31','2026-06-24 02:30:31'),(222,45,'D','Kriteria Level 2 untuk Seperangkat Regulasi: Terdapat regulasi pendukung kebijakan pencegahan korupsi.','Panduan pengujian tingkat 2',NULL,'2026-06-24 02:30:31','2026-06-24 02:30:31'),(223,45,'C','Kriteria Level 3 untuk Seperangkat Regulasi: Terdapat regulasi pendukung kebijakan pencegahan korupsi.','Panduan pengujian tingkat 3',NULL,'2026-06-24 02:30:31','2026-06-24 02:30:31'),(224,45,'B','Kriteria Level 4 untuk Seperangkat Regulasi: Terdapat regulasi pendukung kebijakan pencegahan korupsi.','Panduan pengujian tingkat 4',NULL,'2026-06-24 02:30:31','2026-06-24 02:30:31'),(225,45,'A','Kriteria Level 5 untuk