INSERT INTO `ref_indicators` VALUES (1,1,1,'K/L/D menegakkan integritas dan nilai etika dalam melaksanakan tugas dan fungsi organisasi','2026-06-24 02:30:31','2026-06-24 02:30:31'),(2,2,1,'Tugas dan jabatan dalam organisasi dilaksanakan dan diisi oleh SDM yang kompeten','2026-06-24 02:30:31','2026-06-24 02:30:31'),(3,3,1,'Pimpinan K/L/D menciptakan lingkungan kerja yang kondusif untuk pencapaian tujuan organisasi','2026-06-24 02:30:31','2026-06-24 02:30:31'),(4,3,2,'Pimpinan K/L/D mengalokasikan sumber daya untuk penerapan manajemen risiko','2026-06-24 02:30:31','2026-06-24 02:30:31'),(5,3,3,'Pimpinan K/L/D menggunakan informasi terkait risiko dalam pengambilan keputusan','2026-06-24 02:30:31','2026-06-24 02:30:31'),(6,3,4,'Pimpinan K/L/D mendorong penerapan manajemen risiko, melalui penggunaan kinerja penerapan manajemen risiko sebagai indikator penilaian kinerja','2026-06-24 02:30:31','2026-06-24 02:30:31'),(7,4,1,'Struktur organisasi dibentuk dalam rangka mendukung pencapaian sasaran strategis organisasi','2026-06-24 02:30:31','2026-06-24 02:30:31'),(8,5,1,'Wewenang dan tanggung jawab diberikan kepada pegawai yang tepat sesuai tingkatannya untuk mendukung efektivitas dan efisiensi pelaksanaan kegiatan dalam rangka percepatan pencapaian tujuan organisasi','2026-06-24 02:30:31','2026-06-24 02:30:31'),(9,6,1,'Penerapan kebijakan manajemen dan praktik pembinaan SDM sehingga dapat digunakan secara maksimal untuk mencapai tujuan organisasi','2026-06-24 02:30:31','2026-06-24 02:30:31'),(10,6,2,'Pegawai telah mendapatkan fasilitas untuk meningkatkan kompetensi dan keterampilan terkait manajemen risiko','2026-06-24 02:30:31','2026-06-24 02:30:31'),(11,6,3,'Pegawai memiliki kesadaran terkait manajemen risiko','2026-06-24 02:30:31','2026-06-24 02:30:31'),(12,7,1,'Pengawasan APIP telah dapat memberikan nilai tambah pada perbaikan pengendalian organisasi','2026-06-24 02:30:31','2026-06-24 02:30:31'),(13,8,1,'Pimpinan K/L/D menjalin hubungan kerja yang baik (kemitraan) dengan instansi lain terkait dengan upaya pencapaian tujuan organisasi.','2026-06-24 02:30:31','2026-06-24 02:30:31'),(14,8,2,'Dalam rangka menciptakan hubungan kerja yang baik, K/L/D telah mengidentifikasi, menilai, dan mengelola risiko (termasuk implikasi dari transfer risiko) terkait kemitraan','2026-06-24 02:30:31','2026-06-24 02:30:31'),(15,9,1,'K/L/D telah memiliki Kebijakan Manajemen Risiko','2026-06-24 02:30:31','2026-06-24 02:30:31'),(16,9,2,'Risiko telah teridentifikasi dan  dituangkan dalam register risiko','2026-06-24 02:30:31','2026-06-24 02:30:31'),(17,9,3,'Proses manajemen risiko telah melekat pada proses bisnis K/L/D','2026-06-24 02:30:31','2026-06-24 02:30:31'),(18,10,1,'Seluruh risiko telah dianalisis dampak dan tingkat keterjadiannya','2026-06-24 02:30:31','2026-06-24 02:30:31'),(19,10,2,'K/L/D telah menentukan prioritas risiko','2026-06-24 02:30:31','2026-06-24 02:30:31'),(20,10,3,'K/L/D telah menentukan rencana tindak pengendalian','2026-06-24 02:30:31','2026-06-24 02:30:31'),(21,10,4,'Tindak pengendalian telah diimplementasikan','2026-06-24 02:30:31','2026-06-24 02:30:31'),(22,10,5,'Tindak pengendalian efektif menurunkan risiko','2026-06-24 02:30:31','2026-06-24 02:30:31'),(23,11,1,'Pimpinan K/L/D membandingkan tolok ukur kinerja dengan capaian kinerja secara berkala untuk mengatasi hambatan kinerja, menetapkan strategi perbaikan, dan menilai kinerja suatu unit sampai dengan periode tertentu dalam rangka mengawal pencapaian tujuan organisasi','2026-06-24 02:30:31','2026-06-24 02:30:31'),(24,12,1,'Pembinaan SDM dilakukan sehingga setiap pegawai dapat memberikan manfaat optimal dalam pencapaian tujuan organisasi','2026-06-24 02:30:31','2026-06-24 02:30:31'),(25,13,1,'Pengendalian atas pengelolaan sistem informasi dilakukan untuk memastikan sistem informasi dapat menyajikan data yang akurat dan tepat waktu untuk digunakan oleh pengguna','2026-06-24 02:30:31','2026-06-24 02:30:31'),(26,14,1,'Pengelolaan BMN/D dilakukan untuk menjamin aset tersedia dan dapat digunakan dengan baik oleh pengguna dalam rangka mendukung kinerja organisasi','2026-06-24 02:30:31','2026-06-24 02:30:31'),(27,15,1,'Kegiatan pengendalian atas penetapan dan reviu atas indikator dan ukuran kinerja dilakukan untuk menjamin keandalan ukuran dan ketepatan penetapan indikator masing-masing unit secara berjenjang dibandingkan dengan IKU organisasi','2026-06-24 02:30:31','2026-06-24 02:30:31'),(28,16,1,'Terdapat pemisahan fungsi sehingga seluruh aspek utama transaksi dan kejadian tidak dikendalikan hanya oleh satu orang','2026-06-24 02:30:31','2026-06-24 02:30:31'),(29,17,1,'Terdapat proses untuk memastikan transaksi dan kejadian penting hanya dapat diotorisasi ketika memenuhi persyaratan dan dilakukan oleh pihak yang memiliki kewenangan','2026-06-24 02:30:31','2026-06-24 02:30:31'),(30,18,1,'Terdapat proses untuk memastikan transaksi telah diklasifikasikan dengan layak dan dikelompokkan dengan benar serta dicatat dengan segera sehingga relevan, bernilai, dan berguna bagi manajemen','2026-06-24 02:30:31','2026-06-24 02:30:31'),(31,19,1,'Terdapat pembatasan atas kesempatan dan hak untuk menggunakan, atau memperoleh sumber daya dan mengakses pencatatannya','2026-06-24 02:30:31','2026-06-24 02:30:31'),(32,20,1,'Terdapat pertanggungjawaban seseorang atau unit organisasi dalam mengelola sumber daya yang diberikan/dikuasakan kepadanya dalam rangka pencapaian tujuan organisasi','2026-06-24 02:30:31','2026-06-24 02:30:31'),(33,21,1,'Terdapat pengelolaan, pemeliharaan, dan pendokumentasian secara berkala yang mencakup seluruh SPI serta transaksi dan kejadian penting yang dilaksanakan secara lengkap dan akurat untuk memfasilitasi penelusuran transaksi, kejadian, dan informasi terkait','2026-06-24 02:30:31','2026-06-24 02:30:31'),(34,22,1,'Tersedianya informasi yang relevan untuk kebutuhan internal dan eksternal','2026-06-24 02:30:31','2026-06-24 02:30:31'),(35,22,2,'Pimpinan K/L/D membangun sistem pengaduan','2026-06-24 02:30:31','2026-06-24 02:30:31'),(36,22,3